const BAOSHENG_60_DATA = [
{"no": 1, "displayNo": "第1籤", "level": "吉", "title": "保生大帝第1籤", "poem": ["真金經火煉千回", "此物生成七寶魁", "分明骨骼非常在", "誰肯移來就炭灰"], "story": "【百煉成器】真金火煉是傳統比德意象，以高溫反覆鍛鍊比喻品格與能力經受考驗。", "classicMeaning": "", "plainMeaning": "第1籤主題為百煉成器。四句由真金經火煉千回起筆，經此物生成七寶魁與分明骨骼非常在推進，以誰肯移來就炭灰收束。整體指出：歷經考驗後顯出真材實質。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第1籤把局面寫成此物生成七寶魁，最後以誰肯移來就炭灰收束。套用到事業，應理解為歷經考驗後顯出真材實質；在職位、合作、執行條件與責任界線上屬吉。", "考試": "問考試時，詩中真金經火煉千回指出起因，誰肯移來就炭灰交代結果。兩者合看，表示歷經考驗後顯出真材實質。這項判為吉，須以實際條件是否符合詩中轉機為準。", "求財": "百煉成器不是抽象好壞，而是一個有條件的過程：此物生成七寶魁顯示限制，分明骨骼非常在顯示轉折。對收入來源、交易成本、回收與風險而言，整體為吉。", "失物": "此項要從真金經火煉千回與分明骨骼非常在的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是歷經考驗後顯出真材實質。因此評為吉。", "健康": "第1籤把局面寫成此物生成七寶魁，最後以誰肯移來就炭灰收束。套用到健康，應理解為歷經考驗後顯出真材實質；在症狀變化、診療、休養與危險徵象上屬吉。", "總論": "問總論時，詩中真金經火煉千回指出起因，誰肯移來就炭灰交代結果。兩者合看，表示歷經考驗後顯出真材實質。這項判為吉，須以實際條件是否符合詩中轉機為準。", "婚姻": "百煉成器不是抽象好壞，而是一個有條件的過程：此物生成七寶魁顯示限制，分明骨骼非常在顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為吉。", "人際": "此項要從真金經火煉千回與分明骨骼非常在的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是歷經考驗後顯出真材實質。因此評為吉。", "感情": "第1籤把局面寫成此物生成七寶魁，最後以誰肯移來就炭灰收束。套用到感情，應理解為歷經考驗後顯出真材實質；在雙方意願、互動品質與情緒安全上屬吉。", "出行": "問出行時，詩中真金經火煉千回指出起因，誰肯移來就炭灰交代結果。兩者合看，表示歷經考驗後顯出真材實質。這項判為吉，須以實際條件是否符合詩中轉機為準。", "家宅": "百煉成器不是抽象好壞，而是一個有條件的過程：此物生成七寶魁顯示限制，分明骨骼非常在顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為吉。", "修心建議": "此項要從真金經火煉千回與分明骨骼非常在的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是歷經考驗後顯出真材實質。因此評為吉。"}, "actionAdvice": ["先用真金經火煉千回確認現況，再以此物生成七寶魁找出限制，觀察分明骨骼非常在所示轉折，最後依誰肯移來就炭灰設定完成或停止條件。此籤的實際行動核心是：歷經考驗後顯出真材實質。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 2, "displayNo": "第2籤", "level": "吉", "title": "保生大帝第2籤", "poem": ["日出東方漸吐輝", "銀河星斗自然稀", "次第流光將欲午", "何愁萬里熾炎威"], "story": "【旭日漸盛】日出、星稀、近午構成光勢漸強的時間序列。", "classicMeaning": "", "plainMeaning": "第2籤主題為旭日漸盛。四句由日出東方漸吐輝起筆，經銀河星斗自然稀與次第流光將欲午推進，以何愁萬里熾炎威收束。整體指出：運勢由微明轉為旺盛，但盛極前宜把握分寸。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中日出東方漸吐輝指出起因，何愁萬里熾炎威交代結果。兩者合看，表示運勢由微明轉為旺盛，但盛極前宜把握分寸。這項判為吉，須以實際條件是否符合詩中轉機為準。", "考試": "旭日漸盛不是抽象好壞，而是一個有條件的過程：銀河星斗自然稀顯示限制，次第流光將欲午顯示轉折。對準備深度、評核時機與臨場表現而言，整體為吉。", "求財": "此項要從日出東方漸吐輝與次第流光將欲午的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是運勢由微明轉為旺盛，但盛極前宜把握分寸。因此評為吉。", "失物": "第2籤把局面寫成銀河星斗自然稀，最後以何愁萬里熾炎威收束。套用到失物，應理解為運勢由微明轉為旺盛，但盛極前宜把握分寸；在遺失路徑、可追查線索與尋回時效上屬吉。", "健康": "問健康時，詩中日出東方漸吐輝指出起因，何愁萬里熾炎威交代結果。兩者合看，表示運勢由微明轉為旺盛，但盛極前宜把握分寸。這項判為吉，須以實際條件是否符合詩中轉機為準。", "總論": "旭日漸盛不是抽象好壞，而是一個有條件的過程：銀河星斗自然稀顯示限制，次第流光將欲午顯示轉折。對整體局勢、主要限制與轉機而言，整體為吉。", "婚姻": "此項要從日出東方漸吐輝與次第流光將欲午的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是運勢由微明轉為旺盛，但盛極前宜把握分寸。因此評為吉。", "人際": "第2籤把局面寫成銀河星斗自然稀，最後以何愁萬里熾炎威收束。套用到人際，應理解為運勢由微明轉為旺盛，但盛極前宜把握分寸；在信任、貴人、小人與溝通界線上屬吉。", "感情": "問感情時，詩中日出東方漸吐輝指出起因，何愁萬里熾炎威交代結果。兩者合看，表示運勢由微明轉為旺盛，但盛極前宜把握分寸。這項判為吉，須以實際條件是否符合詩中轉機為準。", "出行": "旭日漸盛不是抽象好壞，而是一個有條件的過程：銀河星斗自然稀顯示限制，次第流光將欲午顯示轉折。對交通條件、方向、時機與人身安全而言，整體為吉。", "家宅": "此項要從日出東方漸吐輝與次第流光將欲午的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是運勢由微明轉為旺盛，但盛極前宜把握分寸。因此評為吉。", "修心建議": "第2籤把局面寫成銀河星斗自然稀，最後以何愁萬里熾炎威收束。套用到修心建議，應理解為運勢由微明轉為旺盛，但盛極前宜把握分寸；在品格、節制、反省與實際改過上屬吉。"}, "actionAdvice": ["先用日出東方漸吐輝確認現況，再以銀河星斗自然稀找出限制，觀察次第流光將欲午所示轉折，最後依何愁萬里熾炎威設定完成或停止條件。此籤的實際行動核心是：運勢由微明轉為旺盛，但盛極前宜把握分寸。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 3, "displayNo": "第3籤", "level": "平", "title": "保生大帝第3籤", "poem": ["寶沈滄海欲親尋", "魚鱉黿鼉敢有侵", "巨浪滔天君莫管", "陽光已久照君心"], "story": "【滄海尋寶】滄海、黿鼉與巨浪皆是險阻意象，寶物則象徵難得成果。", "classicMeaning": "", "plainMeaning": "第3籤主題為滄海尋寶。四句由寶沈滄海欲親尋起筆，經魚鱉黿鼉敢有侵與巨浪滔天君莫管推進，以陽光已久照君心收束。整體指出：外境雖險，內心有定見才可能取得深藏之寶。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "滄海尋寶不是抽象好壞，而是一個有條件的過程：魚鱉黿鼉敢有侵顯示限制，巨浪滔天君莫管顯示轉折。對職位、合作、執行條件與責任界線而言，整體為平。", "考試": "此項要從寶沈滄海欲親尋與巨浪滔天君莫管的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是外境雖險，內心有定見才可能取得深藏之寶。因此評為平。", "求財": "第3籤把局面寫成魚鱉黿鼉敢有侵，最後以陽光已久照君心收束。套用到求財，應理解為外境雖險，內心有定見才可能取得深藏之寶；在收入來源、交易成本、回收與風險上屬平。", "失物": "問失物時，詩中寶沈滄海欲親尋指出起因，陽光已久照君心交代結果。兩者合看，表示外境雖險，內心有定見才可能取得深藏之寶。這項判為平，須以實際條件是否符合詩中轉機為準。", "健康": "滄海尋寶不是抽象好壞，而是一個有條件的過程：魚鱉黿鼉敢有侵顯示限制，巨浪滔天君莫管顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為平。", "總論": "此項要從寶沈滄海欲親尋與巨浪滔天君莫管的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是外境雖險，內心有定見才可能取得深藏之寶。因此評為平。", "婚姻": "第3籤把局面寫成魚鱉黿鼉敢有侵，最後以陽光已久照君心收束。套用到婚姻，應理解為外境雖險，內心有定見才可能取得深藏之寶；在婚約、家庭共識、責任與長期相處上屬平。", "人際": "問人際時，詩中寶沈滄海欲親尋指出起因，陽光已久照君心交代結果。兩者合看，表示外境雖險，內心有定見才可能取得深藏之寶。這項判為平，須以實際條件是否符合詩中轉機為準。", "感情": "滄海尋寶不是抽象好壞，而是一個有條件的過程：魚鱉黿鼉敢有侵顯示限制，巨浪滔天君莫管顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為平。", "出行": "此項要從寶沈滄海欲親尋與巨浪滔天君莫管的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是外境雖險，內心有定見才可能取得深藏之寶。因此評為平。", "家宅": "第3籤把局面寫成魚鱉黿鼉敢有侵，最後以陽光已久照君心收束。套用到家宅，應理解為外境雖險，內心有定見才可能取得深藏之寶；在家庭安寧、居所、修繕與財產安排上屬平。", "修心建議": "問修心建議時，詩中寶沈滄海欲親尋指出起因，陽光已久照君心交代結果。兩者合看，表示外境雖險，內心有定見才可能取得深藏之寶。這項判為平，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用寶沈滄海欲親尋確認現況，再以魚鱉黿鼉敢有侵找出限制，觀察巨浪滔天君莫管所示轉折，最後依陽光已久照君心設定完成或停止條件。此籤的實際行動核心是：外境雖險，內心有定見才可能取得深藏之寶。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 4, "displayNo": "第4籤", "level": "吉", "title": "保生大帝第4籤", "poem": ["君思千里任遨遊", "動用經營自往求", "雲翳欲遮風已吹", "一輪明月滿天秋"], "story": "【雲散月明】雲翳遮月而風先起，是障礙將退、真相復明的常見詩歌意象。", "classicMeaning": "", "plainMeaning": "第4籤主題為雲散月明。四句由君思千里任遨遊起筆，經動用經營自往求與雲翳欲遮風已吹推進，以一輪明月滿天秋收束。整體指出：靠自身經營穿越短暫遮蔽。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從君思千里任遨遊與雲翳欲遮風已吹的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是靠自身經營穿越短暫遮蔽。因此評為吉。", "考試": "第4籤把局面寫成動用經營自往求，最後以一輪明月滿天秋收束。套用到考試，應理解為靠自身經營穿越短暫遮蔽；在準備深度、評核時機與臨場表現上屬吉。", "求財": "問求財時，詩中君思千里任遨遊指出起因，一輪明月滿天秋交代結果。兩者合看，表示靠自身經營穿越短暫遮蔽。這項判為吉，須以實際條件是否符合詩中轉機為準。", "失物": "雲散月明不是抽象好壞，而是一個有條件的過程：動用經營自往求顯示限制，雲翳欲遮風已吹顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為吉。", "健康": "此項要從君思千里任遨遊與雲翳欲遮風已吹的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是靠自身經營穿越短暫遮蔽。因此評為吉。", "總論": "第4籤把局面寫成動用經營自往求，最後以一輪明月滿天秋收束。套用到總論，應理解為靠自身經營穿越短暫遮蔽；在整體局勢、主要限制與轉機上屬吉。", "婚姻": "問婚姻時，詩中君思千里任遨遊指出起因，一輪明月滿天秋交代結果。兩者合看，表示靠自身經營穿越短暫遮蔽。這項判為吉，須以實際條件是否符合詩中轉機為準。", "人際": "雲散月明不是抽象好壞，而是一個有條件的過程：動用經營自往求顯示限制，雲翳欲遮風已吹顯示轉折。對信任、貴人、小人與溝通界線而言，整體為吉。", "感情": "此項要從君思千里任遨遊與雲翳欲遮風已吹的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是靠自身經營穿越短暫遮蔽。因此評為吉。", "出行": "第4籤把局面寫成動用經營自往求，最後以一輪明月滿天秋收束。套用到出行，應理解為靠自身經營穿越短暫遮蔽；在交通條件、方向、時機與人身安全上屬大吉。", "家宅": "問家宅時，詩中君思千里任遨遊指出起因，一輪明月滿天秋交代結果。兩者合看，表示靠自身經營穿越短暫遮蔽。這項判為吉，須以實際條件是否符合詩中轉機為準。", "修心建議": "雲散月明不是抽象好壞，而是一個有條件的過程：動用經營自往求顯示限制，雲翳欲遮風已吹顯示轉折。對品格、節制、反省與實際改過而言，整體為吉。"}, "actionAdvice": ["先用君思千里任遨遊確認現況，再以動用經營自往求找出限制，觀察雲翳欲遮風已吹所示轉折，最後依一輪明月滿天秋設定完成或停止條件。此籤的實際行動核心是：靠自身經營穿越短暫遮蔽。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 5, "displayNo": "第5籤", "level": "偏弱", "title": "保生大帝第5籤", "poem": ["勸君改行禮金容", "寶灶頻添好香濃", "災禍不除祥不至", "宜先急掃此塵空"], "story": "【先除積垢】掃塵兼具實際清潔與滌除雜念、過失的宗教象徵。", "classicMeaning": "", "plainMeaning": "第5籤主題為先除積垢。四句由勸君改行禮金容起筆，經寶灶頻添好香濃與災禍不除祥不至推進，以宜先急掃此塵空收束。整體指出：先改過與清理問題，吉祥才有落腳處。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第5籤把局面寫成寶灶頻添好香濃，最後以宜先急掃此塵空收束。套用到事業，應理解為先改過與清理問題，吉祥才有落腳處；在職位、合作、執行條件與責任界線上屬偏弱。", "考試": "問考試時，詩中勸君改行禮金容指出起因，宜先急掃此塵空交代結果。兩者合看，表示先改過與清理問題，吉祥才有落腳處。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "求財": "先除積垢不是抽象好壞，而是一個有條件的過程：寶灶頻添好香濃顯示限制，災禍不除祥不至顯示轉折。對收入來源、交易成本、回收與風險而言，整體為偏弱。", "失物": "此項要從勸君改行禮金容與災禍不除祥不至的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是先改過與清理問題，吉祥才有落腳處。因此評為偏弱。", "健康": "第5籤把局面寫成寶灶頻添好香濃，最後以宜先急掃此塵空收束。套用到健康，應理解為先改過與清理問題，吉祥才有落腳處；在症狀變化、診療、休養與危險徵象上屬偏弱。", "總論": "問總論時，詩中勸君改行禮金容指出起因，宜先急掃此塵空交代結果。兩者合看，表示先改過與清理問題，吉祥才有落腳處。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "婚姻": "先除積垢不是抽象好壞，而是一個有條件的過程：寶灶頻添好香濃顯示限制，災禍不除祥不至顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為偏弱。", "人際": "此項要從勸君改行禮金容與災禍不除祥不至的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是先改過與清理問題，吉祥才有落腳處。因此評為偏弱。", "感情": "第5籤把局面寫成寶灶頻添好香濃，最後以宜先急掃此塵空收束。套用到感情，應理解為先改過與清理問題，吉祥才有落腳處；在雙方意願、互動品質與情緒安全上屬偏弱。", "出行": "問出行時，詩中勸君改行禮金容指出起因，宜先急掃此塵空交代結果。兩者合看，表示先改過與清理問題，吉祥才有落腳處。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "家宅": "先除積垢不是抽象好壞，而是一個有條件的過程：寶灶頻添好香濃顯示限制，災禍不除祥不至顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為偏弱。", "修心建議": "此項要從勸君改行禮金容與災禍不除祥不至的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是先改過與清理問題，吉祥才有落腳處。因此評為偏弱。"}, "actionAdvice": ["先用勸君改行禮金容確認現況，再以寶灶頻添好香濃找出限制，觀察災禍不除祥不至所示轉折，最後依宜先急掃此塵空設定完成或停止條件。此籤的實際行動核心是：先改過與清理問題，吉祥才有落腳處。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 6, "displayNo": "第6籤", "level": "偏弱", "title": "保生大帝第6籤", "poem": ["他家哀喜休相問", "莫與筵中競酒漿", "無事閉門家中坐", "惟憑旦夕一爐香"], "story": "【閉門避事】競酒、問哀喜皆指涉社交場合，詩意重點是節制與避禍。", "classicMeaning": "", "plainMeaning": "第6籤主題為閉門避事。四句由他家哀喜休相問起筆，經莫與筵中競酒漿與無事閉門家中坐推進，以惟憑旦夕一爐香收束。整體指出：遠離無謂應酬與他人紛爭。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中他家哀喜休相問指出起因，惟憑旦夕一爐香交代結果。兩者合看，表示遠離無謂應酬與他人紛爭。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "考試": "閉門避事不是抽象好壞，而是一個有條件的過程：莫與筵中競酒漿顯示限制，無事閉門家中坐顯示轉折。對準備深度、評核時機與臨場表現而言，整體為偏弱。", "求財": "此項要從他家哀喜休相問與無事閉門家中坐的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是遠離無謂應酬與他人紛爭。因此評為偏弱。", "失物": "第6籤把局面寫成莫與筵中競酒漿，最後以惟憑旦夕一爐香收束。套用到失物，應理解為遠離無謂應酬與他人紛爭；在遺失路徑、可追查線索與尋回時效上屬偏弱。", "健康": "問健康時，詩中他家哀喜休相問指出起因，惟憑旦夕一爐香交代結果。兩者合看，表示遠離無謂應酬與他人紛爭。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "總論": "閉門避事不是抽象好壞，而是一個有條件的過程：莫與筵中競酒漿顯示限制，無事閉門家中坐顯示轉折。對整體局勢、主要限制與轉機而言，整體為偏弱。", "婚姻": "此項要從他家哀喜休相問與無事閉門家中坐的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是遠離無謂應酬與他人紛爭。因此評為偏弱。", "人際": "第6籤把局面寫成莫與筵中競酒漿，最後以惟憑旦夕一爐香收束。套用到人際，應理解為遠離無謂應酬與他人紛爭；在信任、貴人、小人與溝通界線上屬偏弱。", "感情": "問感情時，詩中他家哀喜休相問指出起因，惟憑旦夕一爐香交代結果。兩者合看，表示遠離無謂應酬與他人紛爭。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "出行": "閉門避事不是抽象好壞，而是一個有條件的過程：莫與筵中競酒漿顯示限制，無事閉門家中坐顯示轉折。對交通條件、方向、時機與人身安全而言，整體為偏弱。", "家宅": "此項要從他家哀喜休相問與無事閉門家中坐的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是遠離無謂應酬與他人紛爭。因此評為偏弱。", "修心建議": "第6籤把局面寫成莫與筵中競酒漿，最後以惟憑旦夕一爐香收束。套用到修心建議，應理解為遠離無謂應酬與他人紛爭；在品格、節制、反省與實際改過上屬偏弱。"}, "actionAdvice": ["先用他家哀喜休相問確認現況，再以莫與筵中競酒漿找出限制，觀察無事閉門家中坐所示轉折，最後依惟憑旦夕一爐香設定完成或停止條件。此籤的實際行動核心是：遠離無謂應酬與他人紛爭。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 7, "displayNo": "第7籤", "level": "偏弱", "title": "保生大帝第7籤", "poem": ["枯木庭前欲長芽", "金刀為剪不放花", "誠心自有誠心報", "莫作當時酒價賒"], "story": "【新芽受剪】枯木發芽本是復甦，金刀剪花則表示機會在成形前受挫。", "classicMeaning": "", "plainMeaning": "第7籤主題為新芽受剪。四句由枯木庭前欲長芽起筆，經金刀為剪不放花與誠心自有誠心報推進，以莫作當時酒價賒收束。整體指出：轉機初現卻遭阻斷，須以誠信補救。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "新芽受剪不是抽象好壞，而是一個有條件的過程：金刀為剪不放花顯示限制，誠心自有誠心報顯示轉折。對職位、合作、執行條件與責任界線而言，整體為偏弱。", "考試": "此項要從枯木庭前欲長芽與誠心自有誠心報的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是轉機初現卻遭阻斷，須以誠信補救。因此評為偏弱。", "求財": "第7籤把局面寫成金刀為剪不放花，最後以莫作當時酒價賒收束。套用到求財，應理解為轉機初現卻遭阻斷，須以誠信補救；在收入來源、交易成本、回收與風險上屬偏弱。", "失物": "問失物時，詩中枯木庭前欲長芽指出起因，莫作當時酒價賒交代結果。兩者合看，表示轉機初現卻遭阻斷，須以誠信補救。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "健康": "新芽受剪不是抽象好壞，而是一個有條件的過程：金刀為剪不放花顯示限制，誠心自有誠心報顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為偏弱。", "總論": "此項要從枯木庭前欲長芽與誠心自有誠心報的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是轉機初現卻遭阻斷，須以誠信補救。因此評為偏弱。", "婚姻": "第7籤把局面寫成金刀為剪不放花，最後以莫作當時酒價賒收束。套用到婚姻，應理解為轉機初現卻遭阻斷，須以誠信補救；在婚約、家庭共識、責任與長期相處上屬偏弱。", "人際": "問人際時，詩中枯木庭前欲長芽指出起因，莫作當時酒價賒交代結果。兩者合看，表示轉機初現卻遭阻斷，須以誠信補救。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "感情": "新芽受剪不是抽象好壞，而是一個有條件的過程：金刀為剪不放花顯示限制，誠心自有誠心報顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為偏弱。", "出行": "此項要從枯木庭前欲長芽與誠心自有誠心報的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是轉機初現卻遭阻斷，須以誠信補救。因此評為偏弱。", "家宅": "第7籤把局面寫成金刀為剪不放花，最後以莫作當時酒價賒收束。套用到家宅，應理解為轉機初現卻遭阻斷，須以誠信補救；在家庭安寧、居所、修繕與財產安排上屬偏弱。", "修心建議": "問修心建議時，詩中枯木庭前欲長芽指出起因，莫作當時酒價賒交代結果。兩者合看，表示轉機初現卻遭阻斷，須以誠信補救。這項判為偏弱，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用枯木庭前欲長芽確認現況，再以金刀為剪不放花找出限制，觀察誠心自有誠心報所示轉折，最後依莫作當時酒價賒設定完成或停止條件。此籤的實際行動核心是：轉機初現卻遭阻斷，須以誠信補救。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 8, "displayNo": "第8籤", "level": "偏弱", "title": "保生大帝第8籤", "poem": ["有事些些掛在心", "虛勞心力亂搜尋", "閉門只好三緘口", "事大如天總不侵"], "story": "【三緘其口】三緘口源於慎言傳統，強調資訊不足時不妄議。", "classicMeaning": "", "plainMeaning": "第8籤主題為三緘其口。四句由有事些些掛在心起筆，經虛勞心力亂搜尋與閉門只好三緘口推進，以事大如天總不侵收束。整體指出：少言、停止亂搜，反能免受大事牽連。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從有事些些掛在心與閉門只好三緘口的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是少言、停止亂搜，反能免受大事牽連。因此評為偏弱。", "考試": "第8籤把局面寫成虛勞心力亂搜尋，最後以事大如天總不侵收束。套用到考試，應理解為少言、停止亂搜，反能免受大事牽連；在準備深度、評核時機與臨場表現上屬偏弱。", "求財": "問求財時，詩中有事些些掛在心指出起因，事大如天總不侵交代結果。兩者合看，表示少言、停止亂搜，反能免受大事牽連。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "失物": "三緘其口不是抽象好壞，而是一個有條件的過程：虛勞心力亂搜尋顯示限制，閉門只好三緘口顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為偏弱。", "健康": "此項要從有事些些掛在心與閉門只好三緘口的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是少言、停止亂搜，反能免受大事牽連。因此評為偏弱。", "總論": "第8籤把局面寫成虛勞心力亂搜尋，最後以事大如天總不侵收束。套用到總論，應理解為少言、停止亂搜，反能免受大事牽連；在整體局勢、主要限制與轉機上屬偏弱。", "婚姻": "問婚姻時，詩中有事些些掛在心指出起因，事大如天總不侵交代結果。兩者合看，表示少言、停止亂搜，反能免受大事牽連。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "人際": "三緘其口不是抽象好壞，而是一個有條件的過程：虛勞心力亂搜尋顯示限制，閉門只好三緘口顯示轉折。對信任、貴人、小人與溝通界線而言，整體為偏弱。", "感情": "此項要從有事些些掛在心與閉門只好三緘口的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是少言、停止亂搜，反能免受大事牽連。因此評為偏弱。", "出行": "第8籤把局面寫成虛勞心力亂搜尋，最後以事大如天總不侵收束。套用到出行，應理解為少言、停止亂搜，反能免受大事牽連；在交通條件、方向、時機與人身安全上屬偏弱。", "家宅": "問家宅時，詩中有事些些掛在心指出起因，事大如天總不侵交代結果。兩者合看，表示少言、停止亂搜，反能免受大事牽連。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "修心建議": "三緘其口不是抽象好壞，而是一個有條件的過程：虛勞心力亂搜尋顯示限制，閉門只好三緘口顯示轉折。對品格、節制、反省與實際改過而言，整體為偏弱。"}, "actionAdvice": ["先用有事些些掛在心確認現況，再以虛勞心力亂搜尋找出限制，觀察閉門只好三緘口所示轉折，最後依事大如天總不侵設定完成或停止條件。此籤的實際行動核心是：少言、停止亂搜，反能免受大事牽連。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 9, "displayNo": "第9籤", "level": "吉", "title": "保生大帝第9籤", "poem": ["東南西北任去遊", "陰人在內不須憂", "萍蹤自有相逢日", "金璞之資可往求"], "story": "【四方可行】萍蹤象徵流動不定，金璞象徵尚待發掘的價值。", "classicMeaning": "", "plainMeaning": "第9籤主題為四方可行。四句由東南西北任去遊起筆，經陰人在內不須憂與萍蹤自有相逢日推進，以金璞之資可往求收束。整體指出：外出有路、內有人守，漂泊終能相逢。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第9籤把局面寫成陰人在內不須憂，最後以金璞之資可往求收束。套用到事業，應理解為外出有路、內有人守，漂泊終能相逢；在職位、合作、執行條件與責任界線上屬吉。", "考試": "問考試時，詩中東南西北任去遊指出起因，金璞之資可往求交代結果。兩者合看，表示外出有路、內有人守，漂泊終能相逢。這項判為吉，須以實際條件是否符合詩中轉機為準。", "求財": "四方可行不是抽象好壞，而是一個有條件的過程：陰人在內不須憂顯示限制，萍蹤自有相逢日顯示轉折。對收入來源、交易成本、回收與風險而言，整體為吉。", "失物": "此項要從東南西北任去遊與萍蹤自有相逢日的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是外出有路、內有人守，漂泊終能相逢。因此評為吉。", "健康": "第9籤把局面寫成陰人在內不須憂，最後以金璞之資可往求收束。套用到健康，應理解為外出有路、內有人守，漂泊終能相逢；在症狀變化、診療、休養與危險徵象上屬吉。", "總論": "問總論時，詩中東南西北任去遊指出起因，金璞之資可往求交代結果。兩者合看，表示外出有路、內有人守，漂泊終能相逢。這項判為吉，須以實際條件是否符合詩中轉機為準。", "婚姻": "四方可行不是抽象好壞，而是一個有條件的過程：陰人在內不須憂顯示限制，萍蹤自有相逢日顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為吉。", "人際": "此項要從東南西北任去遊與萍蹤自有相逢日的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是外出有路、內有人守，漂泊終能相逢。因此評為吉。", "感情": "第9籤把局面寫成陰人在內不須憂，最後以金璞之資可往求收束。套用到感情，應理解為外出有路、內有人守，漂泊終能相逢；在雙方意願、互動品質與情緒安全上屬吉。", "出行": "問出行時，詩中東南西北任去遊指出起因，金璞之資可往求交代結果。兩者合看，表示外出有路、內有人守，漂泊終能相逢。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "家宅": "四方可行不是抽象好壞，而是一個有條件的過程：陰人在內不須憂顯示限制，萍蹤自有相逢日顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為吉。", "修心建議": "此項要從東南西北任去遊與萍蹤自有相逢日的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是外出有路、內有人守，漂泊終能相逢。因此評為吉。"}, "actionAdvice": ["先用東南西北任去遊確認現況，再以陰人在內不須憂找出限制，觀察萍蹤自有相逢日所示轉折，最後依金璞之資可往求設定完成或停止條件。此籤的實際行動核心是：外出有路、內有人守，漂泊終能相逢。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 10, "displayNo": "第10籤", "level": "吉", "title": "保生大帝第10籤", "poem": ["相遇良媒已過門", "因循日久未成婚", "好事但逢三六九", "何愁美貌不思君"], "story": "【良緣待期】良媒與過門直指婚姻程序；三六九宜理解為時間提示而非必然日期。", "classicMeaning": "", "plainMeaning": "第10籤主題為良緣待期。四句由相遇良媒已過門起筆，經因循日久未成婚與好事但逢三六九推進，以何愁美貌不思君收束。整體指出：條件已具但因循拖延，三六九為流通本應期語。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中相遇良媒已過門指出起因，何愁美貌不思君交代結果。兩者合看，表示條件已具但因循拖延，三六九為流通本應期語。這項判為吉，須以實際條件是否符合詩中轉機為準。", "考試": "良緣待期不是抽象好壞，而是一個有條件的過程：因循日久未成婚顯示限制，好事但逢三六九顯示轉折。對準備深度、評核時機與臨場表現而言，整體為吉。", "求財": "此項要從相遇良媒已過門與好事但逢三六九的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是條件已具但因循拖延，三六九為流通本應期語。因此評為吉。", "失物": "第10籤把局面寫成因循日久未成婚，最後以何愁美貌不思君收束。套用到失物，應理解為條件已具但因循拖延，三六九為流通本應期語；在遺失路徑、可追查線索與尋回時效上屬吉。", "健康": "問健康時，詩中相遇良媒已過門指出起因，何愁美貌不思君交代結果。兩者合看，表示條件已具但因循拖延，三六九為流通本應期語。這項判為吉，須以實際條件是否符合詩中轉機為準。", "總論": "良緣待期不是抽象好壞，而是一個有條件的過程：因循日久未成婚顯示限制，好事但逢三六九顯示轉折。對整體局勢、主要限制與轉機而言，整體為吉。", "婚姻": "此項要從相遇良媒已過門與好事但逢三六九的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是條件已具但因循拖延，三六九為流通本應期語。因此評為大吉。", "人際": "第10籤把局面寫成因循日久未成婚，最後以何愁美貌不思君收束。套用到人際，應理解為條件已具但因循拖延，三六九為流通本應期語；在信任、貴人、小人與溝通界線上屬吉。", "感情": "問感情時，詩中相遇良媒已過門指出起因，何愁美貌不思君交代結果。兩者合看，表示條件已具但因循拖延，三六九為流通本應期語。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "出行": "良緣待期不是抽象好壞，而是一個有條件的過程：因循日久未成婚顯示限制，好事但逢三六九顯示轉折。對交通條件、方向、時機與人身安全而言，整體為吉。", "家宅": "此項要從相遇良媒已過門與好事但逢三六九的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是條件已具但因循拖延，三六九為流通本應期語。因此評為吉。", "修心建議": "第10籤把局面寫成因循日久未成婚，最後以何愁美貌不思君收束。套用到修心建議，應理解為條件已具但因循拖延，三六九為流通本應期語；在品格、節制、反省與實際改過上屬吉。"}, "actionAdvice": ["先用相遇良媒已過門確認現況，再以因循日久未成婚找出限制，觀察好事但逢三六九所示轉折，最後依何愁美貌不思君設定完成或停止條件。此籤的實際行動核心是：條件已具但因循拖延，三六九為流通本應期語。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 11, "displayNo": "第11籤", "level": "偏弱", "title": "保生大帝第11籤", "poem": ["火中言語起交繁", "惹得家堂有是冤", "禍事欲沾君莫染", "一身也免此心煩"], "story": "【止語避冤】火中言語把激烈情緒與口舌衝突連在一起。", "classicMeaning": "", "plainMeaning": "第11籤主題為止語避冤。四句由火中言語起交繁起筆，經惹得家堂有是冤與禍事欲沾君莫染推進，以一身也免此心煩收束。整體指出：火氣言語最易引起家內冤結。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "止語避冤不是抽象好壞，而是一個有條件的過程：惹得家堂有是冤顯示限制，禍事欲沾君莫染顯示轉折。對職位、合作、執行條件與責任界線而言，整體為偏弱。", "考試": "此項要從火中言語起交繁與禍事欲沾君莫染的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是火氣言語最易引起家內冤結。因此評為偏弱。", "求財": "第11籤把局面寫成惹得家堂有是冤，最後以一身也免此心煩收束。套用到求財，應理解為火氣言語最易引起家內冤結；在收入來源、交易成本、回收與風險上屬偏弱。", "失物": "問失物時，詩中火中言語起交繁指出起因，一身也免此心煩交代結果。兩者合看，表示火氣言語最易引起家內冤結。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "健康": "止語避冤不是抽象好壞，而是一個有條件的過程：惹得家堂有是冤顯示限制，禍事欲沾君莫染顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為偏弱。", "總論": "此項要從火中言語起交繁與禍事欲沾君莫染的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是火氣言語最易引起家內冤結。因此評為偏弱。", "婚姻": "第11籤把局面寫成惹得家堂有是冤，最後以一身也免此心煩收束。套用到婚姻，應理解為火氣言語最易引起家內冤結；在婚約、家庭共識、責任與長期相處上屬偏弱。", "人際": "問人際時，詩中火中言語起交繁指出起因，一身也免此心煩交代結果。兩者合看，表示火氣言語最易引起家內冤結。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "感情": "止語避冤不是抽象好壞，而是一個有條件的過程：惹得家堂有是冤顯示限制，禍事欲沾君莫染顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為偏弱。", "出行": "此項要從火中言語起交繁與禍事欲沾君莫染的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是火氣言語最易引起家內冤結。因此評為偏弱。", "家宅": "第11籤把局面寫成惹得家堂有是冤，最後以一身也免此心煩收束。套用到家宅，應理解為火氣言語最易引起家內冤結；在家庭安寧、居所、修繕與財產安排上屬偏弱。", "修心建議": "問修心建議時，詩中火中言語起交繁指出起因，一身也免此心煩交代結果。兩者合看，表示火氣言語最易引起家內冤結。這項判為偏弱，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用火中言語起交繁確認現況，再以惹得家堂有是冤找出限制，觀察禍事欲沾君莫染所示轉折，最後依一身也免此心煩設定完成或停止條件。此籤的實際行動核心是：火氣言語最易引起家內冤結。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 12, "displayNo": "第12籤", "level": "偏弱", "title": "保生大帝第12籤", "poem": ["喜事親臨莫往觀", "哀門咫尺不須看", "且逃野外三天後", "祿馬自然得遂安"], "story": "【暫避穢擾】喜門、哀門與祿馬屬傳統民俗語彙，重點在暫避與恢復秩序。", "classicMeaning": "", "plainMeaning": "第12籤主題為暫避穢擾。四句由喜事親臨莫往觀起筆，經哀門咫尺不須看與且逃野外三天後推進，以祿馬自然得遂安收束。整體指出：短期遠離混雜場合，待三日後再動。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從喜事親臨莫往觀與且逃野外三天後的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是短期遠離混雜場合，待三日後再動。因此評為偏弱。", "考試": "第12籤把局面寫成哀門咫尺不須看，最後以祿馬自然得遂安收束。套用到考試，應理解為短期遠離混雜場合，待三日後再動；在準備深度、評核時機與臨場表現上屬偏弱。", "求財": "問求財時，詩中喜事親臨莫往觀指出起因，祿馬自然得遂安交代結果。兩者合看，表示短期遠離混雜場合，待三日後再動。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "失物": "暫避穢擾不是抽象好壞，而是一個有條件的過程：哀門咫尺不須看顯示限制，且逃野外三天後顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為偏弱。", "健康": "此項要從喜事親臨莫往觀與且逃野外三天後的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是短期遠離混雜場合，待三日後再動。因此評為偏弱。", "總論": "第12籤把局面寫成哀門咫尺不須看，最後以祿馬自然得遂安收束。套用到總論，應理解為短期遠離混雜場合，待三日後再動；在整體局勢、主要限制與轉機上屬偏弱。", "婚姻": "問婚姻時，詩中喜事親臨莫往觀指出起因，祿馬自然得遂安交代結果。兩者合看，表示短期遠離混雜場合，待三日後再動。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "人際": "暫避穢擾不是抽象好壞，而是一個有條件的過程：哀門咫尺不須看顯示限制，且逃野外三天後顯示轉折。對信任、貴人、小人與溝通界線而言，整體為偏弱。", "感情": "此項要從喜事親臨莫往觀與且逃野外三天後的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是短期遠離混雜場合，待三日後再動。因此評為偏弱。", "出行": "第12籤把局面寫成哀門咫尺不須看，最後以祿馬自然得遂安收束。套用到出行，應理解為短期遠離混雜場合，待三日後再動；在交通條件、方向、時機與人身安全上屬偏弱。", "家宅": "問家宅時，詩中喜事親臨莫往觀指出起因，祿馬自然得遂安交代結果。兩者合看，表示短期遠離混雜場合，待三日後再動。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "修心建議": "暫避穢擾不是抽象好壞，而是一個有條件的過程：哀門咫尺不須看顯示限制，且逃野外三天後顯示轉折。對品格、節制、反省與實際改過而言，整體為偏弱。"}, "actionAdvice": ["先用喜事親臨莫往觀確認現況，再以哀門咫尺不須看找出限制，觀察且逃野外三天後所示轉折，最後依祿馬自然得遂安設定完成或停止條件。此籤的實際行動核心是：短期遠離混雜場合，待三日後再動。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 13, "displayNo": "第13籤", "level": "吉", "title": "保生大帝第13籤", "poem": ["匹馬匆匆指去程", "好逑體態自然成", "損言若有來相破", "到底完婚一笑迎"], "story": "【良緣不破】好逑出自《詩經》婚戀語彙，象徵相配伴侶。", "classicMeaning": "", "plainMeaning": "第13籤主題為良緣不破。四句由匹馬匆匆指去程起筆，經好逑體態自然成與損言若有來相破推進，以到底完婚一笑迎收束。整體指出：雖有毀言，婚事最終仍可完成。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第13籤把局面寫成好逑體態自然成，最後以到底完婚一笑迎收束。套用到事業，應理解為雖有毀言，婚事最終仍可完成；在職位、合作、執行條件與責任界線上屬吉。", "考試": "問考試時，詩中匹馬匆匆指去程指出起因，到底完婚一笑迎交代結果。兩者合看，表示雖有毀言，婚事最終仍可完成。這項判為吉，須以實際條件是否符合詩中轉機為準。", "求財": "良緣不破不是抽象好壞，而是一個有條件的過程：好逑體態自然成顯示限制，損言若有來相破顯示轉折。對收入來源、交易成本、回收與風險而言，整體為吉。", "失物": "此項要從匹馬匆匆指去程與損言若有來相破的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是雖有毀言，婚事最終仍可完成。因此評為吉。", "健康": "第13籤把局面寫成好逑體態自然成，最後以到底完婚一笑迎收束。套用到健康，應理解為雖有毀言，婚事最終仍可完成；在症狀變化、診療、休養與危險徵象上屬吉。", "總論": "問總論時，詩中匹馬匆匆指去程指出起因，到底完婚一笑迎交代結果。兩者合看，表示雖有毀言，婚事最終仍可完成。這項判為吉，須以實際條件是否符合詩中轉機為準。", "婚姻": "良緣不破不是抽象好壞，而是一個有條件的過程：好逑體態自然成顯示限制，損言若有來相破顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為大吉。", "人際": "此項要從匹馬匆匆指去程與損言若有來相破的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是雖有毀言，婚事最終仍可完成。因此評為吉。", "感情": "第13籤把局面寫成好逑體態自然成，最後以到底完婚一笑迎收束。套用到感情，應理解為雖有毀言，婚事最終仍可完成；在雙方意願、互動品質與情緒安全上屬大吉。", "出行": "問出行時，詩中匹馬匆匆指去程指出起因，到底完婚一笑迎交代結果。兩者合看，表示雖有毀言，婚事最終仍可完成。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "家宅": "良緣不破不是抽象好壞，而是一個有條件的過程：好逑體態自然成顯示限制，損言若有來相破顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為吉。", "修心建議": "此項要從匹馬匆匆指去程與損言若有來相破的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是雖有毀言，婚事最終仍可完成。因此評為吉。"}, "actionAdvice": ["先用匹馬匆匆指去程確認現況，再以好逑體態自然成找出限制，觀察損言若有來相破所示轉折，最後依到底完婚一笑迎設定完成或停止條件。此籤的實際行動核心是：雖有毀言，婚事最終仍可完成。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 14, "displayNo": "第14籤", "level": "吉", "title": "保生大帝第14籤", "poem": ["片帆渡海任欹斜", "頃刻乘風入遠沙", "忙裡不知分別去", "明朝便是到吾家"], "story": "【乘風歸航】片帆、遠沙、到家形成典型航海行旅意象。", "classicMeaning": "", "plainMeaning": "第14籤主題為乘風歸航。四句由片帆渡海任欹斜起筆，經頃刻乘風入遠沙與忙裡不知分別去推進，以明朝便是到吾家收束。整體指出：舟行雖斜，得風即可迅速抵達。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中片帆渡海任欹斜指出起因，明朝便是到吾家交代結果。兩者合看，表示舟行雖斜，得風即可迅速抵達。這項判為吉，須以實際條件是否符合詩中轉機為準。", "考試": "乘風歸航不是抽象好壞，而是一個有條件的過程：頃刻乘風入遠沙顯示限制，忙裡不知分別去顯示轉折。對準備深度、評核時機與臨場表現而言，整體為吉。", "求財": "此項要從片帆渡海任欹斜與忙裡不知分別去的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是舟行雖斜，得風即可迅速抵達。因此評為吉。", "失物": "第14籤把局面寫成頃刻乘風入遠沙，最後以明朝便是到吾家收束。套用到失物，應理解為舟行雖斜，得風即可迅速抵達；在遺失路徑、可追查線索與尋回時效上屬吉。", "健康": "問健康時，詩中片帆渡海任欹斜指出起因，明朝便是到吾家交代結果。兩者合看，表示舟行雖斜，得風即可迅速抵達。這項判為吉，須以實際條件是否符合詩中轉機為準。", "總論": "乘風歸航不是抽象好壞，而是一個有條件的過程：頃刻乘風入遠沙顯示限制，忙裡不知分別去顯示轉折。對整體局勢、主要限制與轉機而言，整體為吉。", "婚姻": "此項要從片帆渡海任欹斜與忙裡不知分別去的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是舟行雖斜，得風即可迅速抵達。因此評為吉。", "人際": "第14籤把局面寫成頃刻乘風入遠沙，最後以明朝便是到吾家收束。套用到人際，應理解為舟行雖斜，得風即可迅速抵達；在信任、貴人、小人與溝通界線上屬吉。", "感情": "問感情時，詩中片帆渡海任欹斜指出起因，明朝便是到吾家交代結果。兩者合看，表示舟行雖斜，得風即可迅速抵達。這項判為吉，須以實際條件是否符合詩中轉機為準。", "出行": "乘風歸航不是抽象好壞，而是一個有條件的過程：頃刻乘風入遠沙顯示限制，忙裡不知分別去顯示轉折。對交通條件、方向、時機與人身安全而言，整體為大吉。", "家宅": "此項要從片帆渡海任欹斜與忙裡不知分別去的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是舟行雖斜，得風即可迅速抵達。因此評為吉。", "修心建議": "第14籤把局面寫成頃刻乘風入遠沙，最後以明朝便是到吾家收束。套用到修心建議，應理解為舟行雖斜，得風即可迅速抵達；在品格、節制、反省與實際改過上屬吉。"}, "actionAdvice": ["先用片帆渡海任欹斜確認現況，再以頃刻乘風入遠沙找出限制，觀察忙裡不知分別去所示轉折，最後依明朝便是到吾家設定完成或停止條件。此籤的實際行動核心是：舟行雖斜，得風即可迅速抵達。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 15, "displayNo": "第15籤", "level": "吉", "title": "保生大帝第15籤", "poem": ["一輪明月照千家", "銀漢澄清望眼斜", "丹桂分枝長葉在", "纖纖雲翳謾相遮"], "story": "【月桂長青】丹桂常與功名、月宮相連，長葉表示根本仍在。", "classicMeaning": "", "plainMeaning": "第15籤主題為月桂長青。四句由一輪明月照千家起筆，經銀漢澄清望眼斜與丹桂分枝長葉在推進，以纖纖雲翳謾相遮收束。整體指出：根基清明，薄雲不足長久遮蔽。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "月桂長青不是抽象好壞，而是一個有條件的過程：銀漢澄清望眼斜顯示限制，丹桂分枝長葉在顯示轉折。對職位、合作、執行條件與責任界線而言，整體為吉。", "考試": "此項要從一輪明月照千家與丹桂分枝長葉在的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是根基清明，薄雲不足長久遮蔽。因此評為吉。", "求財": "第15籤把局面寫成銀漢澄清望眼斜，最後以纖纖雲翳謾相遮收束。套用到求財，應理解為根基清明，薄雲不足長久遮蔽；在收入來源、交易成本、回收與風險上屬吉。", "失物": "問失物時，詩中一輪明月照千家指出起因，纖纖雲翳謾相遮交代結果。兩者合看，表示根基清明，薄雲不足長久遮蔽。這項判為吉，須以實際條件是否符合詩中轉機為準。", "健康": "月桂長青不是抽象好壞，而是一個有條件的過程：銀漢澄清望眼斜顯示限制，丹桂分枝長葉在顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為吉。", "總論": "此項要從一輪明月照千家與丹桂分枝長葉在的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是根基清明，薄雲不足長久遮蔽。因此評為吉。", "婚姻": "第15籤把局面寫成銀漢澄清望眼斜，最後以纖纖雲翳謾相遮收束。套用到婚姻，應理解為根基清明，薄雲不足長久遮蔽；在婚約、家庭共識、責任與長期相處上屬吉。", "人際": "問人際時，詩中一輪明月照千家指出起因，纖纖雲翳謾相遮交代結果。兩者合看，表示根基清明，薄雲不足長久遮蔽。這項判為吉，須以實際條件是否符合詩中轉機為準。", "感情": "月桂長青不是抽象好壞，而是一個有條件的過程：銀漢澄清望眼斜顯示限制，丹桂分枝長葉在顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為吉。", "出行": "此項要從一輪明月照千家與丹桂分枝長葉在的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是根基清明，薄雲不足長久遮蔽。因此評為吉。", "家宅": "第15籤把局面寫成銀漢澄清望眼斜，最後以纖纖雲翳謾相遮收束。套用到家宅，應理解為根基清明，薄雲不足長久遮蔽；在家庭安寧、居所、修繕與財產安排上屬吉。", "修心建議": "問修心建議時，詩中一輪明月照千家指出起因，纖纖雲翳謾相遮交代結果。兩者合看，表示根基清明，薄雲不足長久遮蔽。這項判為吉，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用一輪明月照千家確認現況，再以銀漢澄清望眼斜找出限制，觀察丹桂分枝長葉在所示轉折，最後依纖纖雲翳謾相遮設定完成或停止條件。此籤的實際行動核心是：根基清明，薄雲不足長久遮蔽。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 16, "displayNo": "第16籤", "level": "平", "title": "保生大帝第16籤", "poem": ["閒遊暗路被侵傷", "渾痛心身不上床", "昨夜焚香祈禱下", "淋漓喜雨得安康"], "story": "【暗路遇雨】喜雨在農耕文化中象徵及時救濟與復甦。", "classicMeaning": "", "plainMeaning": "第16籤主題為暗路遇雨。四句由閒遊暗路被侵傷起筆，經渾痛心身不上床與昨夜焚香祈禱下推進，以淋漓喜雨得安康收束。整體指出：先受暗傷，後得甘雨舒解。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從閒遊暗路被侵傷與昨夜焚香祈禱下的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是先受暗傷，後得甘雨舒解。因此評為平。", "考試": "第16籤把局面寫成渾痛心身不上床，最後以淋漓喜雨得安康收束。套用到考試，應理解為先受暗傷，後得甘雨舒解；在準備深度、評核時機與臨場表現上屬平。", "求財": "問求財時，詩中閒遊暗路被侵傷指出起因，淋漓喜雨得安康交代結果。兩者合看，表示先受暗傷，後得甘雨舒解。這項判為平，須以實際條件是否符合詩中轉機為準。", "失物": "暗路遇雨不是抽象好壞，而是一個有條件的過程：渾痛心身不上床顯示限制，昨夜焚香祈禱下顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為平。", "健康": "此項要從閒遊暗路被侵傷與昨夜焚香祈禱下的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是先受暗傷，後得甘雨舒解。因此評為平。", "總論": "第16籤把局面寫成渾痛心身不上床，最後以淋漓喜雨得安康收束。套用到總論，應理解為先受暗傷，後得甘雨舒解；在整體局勢、主要限制與轉機上屬平。", "婚姻": "問婚姻時，詩中閒遊暗路被侵傷指出起因，淋漓喜雨得安康交代結果。兩者合看，表示先受暗傷，後得甘雨舒解。這項判為平，須以實際條件是否符合詩中轉機為準。", "人際": "暗路遇雨不是抽象好壞，而是一個有條件的過程：渾痛心身不上床顯示限制，昨夜焚香祈禱下顯示轉折。對信任、貴人、小人與溝通界線而言，整體為平。", "感情": "此項要從閒遊暗路被侵傷與昨夜焚香祈禱下的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是先受暗傷，後得甘雨舒解。因此評為平。", "出行": "第16籤把局面寫成渾痛心身不上床，最後以淋漓喜雨得安康收束。套用到出行，應理解為先受暗傷，後得甘雨舒解；在交通條件、方向、時機與人身安全上屬偏弱。", "家宅": "問家宅時，詩中閒遊暗路被侵傷指出起因，淋漓喜雨得安康交代結果。兩者合看，表示先受暗傷，後得甘雨舒解。這項判為平，須以實際條件是否符合詩中轉機為準。", "修心建議": "暗路遇雨不是抽象好壞，而是一個有條件的過程：渾痛心身不上床顯示限制，昨夜焚香祈禱下顯示轉折。對品格、節制、反省與實際改過而言，整體為平。"}, "actionAdvice": ["先用閒遊暗路被侵傷確認現況，再以渾痛心身不上床找出限制，觀察昨夜焚香祈禱下所示轉折，最後依淋漓喜雨得安康設定完成或停止條件。此籤的實際行動核心是：先受暗傷，後得甘雨舒解。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 17, "displayNo": "第17籤", "level": "吉", "title": "保生大帝第17籤", "poem": ["災不厭禳禳自消", "禍因作福福宜生", "神前旦夕焚香叩", "萬事自然保安寧"], "story": "【修福禳災】禳災是傳統祭祀語彙，但現代解讀應重實際補救。", "classicMeaning": "", "plainMeaning": "第17籤主題為修福禳災。四句由災不厭禳禳自消起筆，經禍因作福福宜生與神前旦夕焚香叩推進，以萬事自然保安寧收束。整體指出：以善行、反省與持續祈禱轉化災厄。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第17籤把局面寫成禍因作福福宜生，最後以萬事自然保安寧收束。套用到事業，應理解為以善行、反省與持續祈禱轉化災厄；在職位、合作、執行條件與責任界線上屬吉。", "考試": "問考試時，詩中災不厭禳禳自消指出起因，萬事自然保安寧交代結果。兩者合看，表示以善行、反省與持續祈禱轉化災厄。這項判為吉，須以實際條件是否符合詩中轉機為準。", "求財": "修福禳災不是抽象好壞，而是一個有條件的過程：禍因作福福宜生顯示限制，神前旦夕焚香叩顯示轉折。對收入來源、交易成本、回收與風險而言，整體為吉。", "失物": "此項要從災不厭禳禳自消與神前旦夕焚香叩的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是以善行、反省與持續祈禱轉化災厄。因此評為吉。", "健康": "第17籤把局面寫成禍因作福福宜生，最後以萬事自然保安寧收束。套用到健康，應理解為以善行、反省與持續祈禱轉化災厄；在症狀變化、診療、休養與危險徵象上屬大吉。", "總論": "問總論時，詩中災不厭禳禳自消指出起因，萬事自然保安寧交代結果。兩者合看，表示以善行、反省與持續祈禱轉化災厄。這項判為吉，須以實際條件是否符合詩中轉機為準。", "婚姻": "修福禳災不是抽象好壞，而是一個有條件的過程：禍因作福福宜生顯示限制，神前旦夕焚香叩顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為吉。", "人際": "此項要從災不厭禳禳自消與神前旦夕焚香叩的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是以善行、反省與持續祈禱轉化災厄。因此評為吉。", "感情": "第17籤把局面寫成禍因作福福宜生，最後以萬事自然保安寧收束。套用到感情，應理解為以善行、反省與持續祈禱轉化災厄；在雙方意願、互動品質與情緒安全上屬吉。", "出行": "問出行時，詩中災不厭禳禳自消指出起因，萬事自然保安寧交代結果。兩者合看，表示以善行、反省與持續祈禱轉化災厄。這項判為吉，須以實際條件是否符合詩中轉機為準。", "家宅": "修福禳災不是抽象好壞，而是一個有條件的過程：禍因作福福宜生顯示限制，神前旦夕焚香叩顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為吉。", "修心建議": "此項要從災不厭禳禳自消與神前旦夕焚香叩的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是以善行、反省與持續祈禱轉化災厄。因此評為吉。"}, "actionAdvice": ["先用災不厭禳禳自消確認現況，再以禍因作福福宜生找出限制，觀察神前旦夕焚香叩所示轉折，最後依萬事自然保安寧設定完成或停止條件。此籤的實際行動核心是：以善行、反省與持續祈禱轉化災厄。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 18, "displayNo": "第18籤", "level": "吉", "title": "保生大帝第18籤", "poem": ["匆匆匹馬掛金鞍", "金鐙纔敲去不難", "大道坦平君速進", "貴人迎接樂團圓"], "story": "【大道速進】金鞍、金鐙與大道皆是啟程順利、身分提升的意象。", "classicMeaning": "", "plainMeaning": "第18籤主題為大道速進。四句由匆匆匹馬掛金鞍起筆，經金鐙纔敲去不難與大道坦平君速進推進，以貴人迎接樂團圓收束。整體指出：道路平坦、貴人迎接，宜抓緊前進。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中匆匆匹馬掛金鞍指出起因，貴人迎接樂團圓交代結果。兩者合看，表示道路平坦、貴人迎接，宜抓緊前進。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "考試": "大道速進不是抽象好壞，而是一個有條件的過程：金鐙纔敲去不難顯示限制，大道坦平君速進顯示轉折。對準備深度、評核時機與臨場表現而言，整體為大吉。", "求財": "此項要從匆匆匹馬掛金鞍與大道坦平君速進的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是道路平坦、貴人迎接，宜抓緊前進。因此評為大吉。", "失物": "第18籤把局面寫成金鐙纔敲去不難，最後以貴人迎接樂團圓收束。套用到失物，應理解為道路平坦、貴人迎接，宜抓緊前進；在遺失路徑、可追查線索與尋回時效上屬吉。", "健康": "問健康時，詩中匆匆匹馬掛金鞍指出起因，貴人迎接樂團圓交代結果。兩者合看，表示道路平坦、貴人迎接，宜抓緊前進。這項判為吉，須以實際條件是否符合詩中轉機為準。", "總論": "大道速進不是抽象好壞，而是一個有條件的過程：金鐙纔敲去不難顯示限制，大道坦平君速進顯示轉折。對整體局勢、主要限制與轉機而言，整體為吉。", "婚姻": "此項要從匆匆匹馬掛金鞍與大道坦平君速進的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是道路平坦、貴人迎接，宜抓緊前進。因此評為吉。", "人際": "第18籤把局面寫成金鐙纔敲去不難，最後以貴人迎接樂團圓收束。套用到人際，應理解為道路平坦、貴人迎接，宜抓緊前進；在信任、貴人、小人與溝通界線上屬吉。", "感情": "問感情時，詩中匆匆匹馬掛金鞍指出起因，貴人迎接樂團圓交代結果。兩者合看，表示道路平坦、貴人迎接，宜抓緊前進。這項判為吉，須以實際條件是否符合詩中轉機為準。", "出行": "大道速進不是抽象好壞，而是一個有條件的過程：金鐙纔敲去不難顯示限制，大道坦平君速進顯示轉折。對交通條件、方向、時機與人身安全而言，整體為大吉。", "家宅": "此項要從匆匆匹馬掛金鞍與大道坦平君速進的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是道路平坦、貴人迎接，宜抓緊前進。因此評為吉。", "修心建議": "第18籤把局面寫成金鐙纔敲去不難，最後以貴人迎接樂團圓收束。套用到修心建議，應理解為道路平坦、貴人迎接，宜抓緊前進；在品格、節制、反省與實際改過上屬吉。"}, "actionAdvice": ["先用匆匆匹馬掛金鞍確認現況，再以金鐙纔敲去不難找出限制，觀察大道坦平君速進所示轉折，最後依貴人迎接樂團圓設定完成或停止條件。此籤的實際行動核心是：道路平坦、貴人迎接，宜抓緊前進。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 19, "displayNo": "第19籤", "level": "平", "title": "保生大帝第19籤", "poem": ["故人遺愛饋蒸豚", "莫較樽前酒下分", "報道門前嘉客到", "不知多少可留存"], "story": "【嘉客餽贈】蒸豚與樽酒代表宴饗，詩中提醒不要在席間斤斤計較。", "classicMeaning": "", "plainMeaning": "第19籤主題為嘉客餽贈。四句由故人遺愛饋蒸豚起筆，經莫較樽前酒下分與報道門前嘉客到推進，以不知多少可留存收束。整體指出：有情分與資源來臨，但可留多少取決於節制。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "嘉客餽贈不是抽象好壞，而是一個有條件的過程：莫較樽前酒下分顯示限制，報道門前嘉客到顯示轉折。對職位、合作、執行條件與責任界線而言，整體為平。", "考試": "此項要從故人遺愛饋蒸豚與報道門前嘉客到的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是有情分與資源來臨，但可留多少取決於節制。因此評為平。", "求財": "第19籤把局面寫成莫較樽前酒下分，最後以不知多少可留存收束。套用到求財，應理解為有情分與資源來臨，但可留多少取決於節制；在收入來源、交易成本、回收與風險上屬平。", "失物": "問失物時，詩中故人遺愛饋蒸豚指出起因，不知多少可留存交代結果。兩者合看，表示有情分與資源來臨，但可留多少取決於節制。這項判為平，須以實際條件是否符合詩中轉機為準。", "健康": "嘉客餽贈不是抽象好壞，而是一個有條件的過程：莫較樽前酒下分顯示限制，報道門前嘉客到顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為平。", "總論": "此項要從故人遺愛饋蒸豚與報道門前嘉客到的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是有情分與資源來臨，但可留多少取決於節制。因此評為平。", "婚姻": "第19籤把局面寫成莫較樽前酒下分，最後以不知多少可留存收束。套用到婚姻，應理解為有情分與資源來臨，但可留多少取決於節制；在婚約、家庭共識、責任與長期相處上屬平。", "人際": "問人際時，詩中故人遺愛饋蒸豚指出起因，不知多少可留存交代結果。兩者合看，表示有情分與資源來臨，但可留多少取決於節制。這項判為平，須以實際條件是否符合詩中轉機為準。", "感情": "嘉客餽贈不是抽象好壞，而是一個有條件的過程：莫較樽前酒下分顯示限制，報道門前嘉客到顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為平。", "出行": "此項要從故人遺愛饋蒸豚與報道門前嘉客到的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是有情分與資源來臨，但可留多少取決於節制。因此評為平。", "家宅": "第19籤把局面寫成莫較樽前酒下分，最後以不知多少可留存收束。套用到家宅，應理解為有情分與資源來臨，但可留多少取決於節制；在家庭安寧、居所、修繕與財產安排上屬平。", "修心建議": "問修心建議時，詩中故人遺愛饋蒸豚指出起因，不知多少可留存交代結果。兩者合看，表示有情分與資源來臨，但可留多少取決於節制。這項判為平，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用故人遺愛饋蒸豚確認現況，再以莫較樽前酒下分找出限制，觀察報道門前嘉客到所示轉折，最後依不知多少可留存設定完成或停止條件。此籤的實際行動核心是：有情分與資源來臨，但可留多少取決於節制。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 20, "displayNo": "第20籤", "level": "吉", "title": "保生大帝第20籤", "poem": ["扁舟一葉泛來輕", "五夜無聲載月明", "任是長江風浪闊", "不勞心力自登瀛"], "story": "【月夜登瀛】登瀛可泛指抵達佳境，不必強附特定人物故事。", "classicMeaning": "", "plainMeaning": "第20籤主題為月夜登瀛。四句由扁舟一葉泛來輕起筆，經五夜無聲載月明與任是長江風浪闊推進，以不勞心力自登瀛收束。整體指出：以柔順輕舟越過大江，事情省力而成。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從扁舟一葉泛來輕與任是長江風浪闊的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是以柔順輕舟越過大江，事情省力而成。因此評為吉。", "考試": "第20籤把局面寫成五夜無聲載月明，最後以不勞心力自登瀛收束。套用到考試，應理解為以柔順輕舟越過大江，事情省力而成；在準備深度、評核時機與臨場表現上屬吉。", "求財": "問求財時，詩中扁舟一葉泛來輕指出起因，不勞心力自登瀛交代結果。兩者合看，表示以柔順輕舟越過大江，事情省力而成。這項判為吉，須以實際條件是否符合詩中轉機為準。", "失物": "月夜登瀛不是抽象好壞，而是一個有條件的過程：五夜無聲載月明顯示限制，任是長江風浪闊顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為吉。", "健康": "此項要從扁舟一葉泛來輕與任是長江風浪闊的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是以柔順輕舟越過大江，事情省力而成。因此評為吉。", "總論": "第20籤把局面寫成五夜無聲載月明，最後以不勞心力自登瀛收束。套用到總論，應理解為以柔順輕舟越過大江，事情省力而成；在整體局勢、主要限制與轉機上屬吉。", "婚姻": "問婚姻時，詩中扁舟一葉泛來輕指出起因，不勞心力自登瀛交代結果。兩者合看，表示以柔順輕舟越過大江，事情省力而成。這項判為吉，須以實際條件是否符合詩中轉機為準。", "人際": "月夜登瀛不是抽象好壞，而是一個有條件的過程：五夜無聲載月明顯示限制，任是長江風浪闊顯示轉折。對信任、貴人、小人與溝通界線而言，整體為吉。", "感情": "此項要從扁舟一葉泛來輕與任是長江風浪闊的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是以柔順輕舟越過大江，事情省力而成。因此評為吉。", "出行": "第20籤把局面寫成五夜無聲載月明，最後以不勞心力自登瀛收束。套用到出行，應理解為以柔順輕舟越過大江，事情省力而成；在交通條件、方向、時機與人身安全上屬大吉。", "家宅": "問家宅時，詩中扁舟一葉泛來輕指出起因，不勞心力自登瀛交代結果。兩者合看，表示以柔順輕舟越過大江，事情省力而成。這項判為吉，須以實際條件是否符合詩中轉機為準。", "修心建議": "月夜登瀛不是抽象好壞，而是一個有條件的過程：五夜無聲載月明顯示限制，任是長江風浪闊顯示轉折。對品格、節制、反省與實際改過而言，整體為吉。"}, "actionAdvice": ["先用扁舟一葉泛來輕確認現況，再以五夜無聲載月明找出限制，觀察任是長江風浪闊所示轉折，最後依不勞心力自登瀛設定完成或停止條件。此籤的實際行動核心是：以柔順輕舟越過大江，事情省力而成。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 21, "displayNo": "第21籤", "level": "平", "title": "保生大帝第21籤", "poem": ["財帛相交莫信讒", "信纔誠恐有疑貪", "寸心若得存中正", "去後何須說二三"], "story": "【財交守正】寸心中正是傳統倫理語彙，指交易中守信守分。", "classicMeaning": "", "plainMeaning": "第21籤主題為財交守正。四句由財帛相交莫信讒起筆，經信纔誠恐有疑貪與寸心若得存中正推進，以去後何須說二三收束。整體指出：金錢往來最怕讒言、猜疑與貪念。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第21籤把局面寫成信纔誠恐有疑貪，最後以去後何須說二三收束。套用到事業，應理解為金錢往來最怕讒言、猜疑與貪念；在職位、合作、執行條件與責任界線上屬吉。", "考試": "問考試時，詩中財帛相交莫信讒指出起因，去後何須說二三交代結果。兩者合看，表示金錢往來最怕讒言、猜疑與貪念。這項判為吉，須以實際條件是否符合詩中轉機為準。", "求財": "財交守正不是抽象好壞，而是一個有條件的過程：信纔誠恐有疑貪顯示限制，寸心若得存中正顯示轉折。對收入來源、交易成本、回收與風險而言，整體為吉。", "失物": "此項要從財帛相交莫信讒與寸心若得存中正的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是金錢往來最怕讒言、猜疑與貪念。因此評為平。", "健康": "第21籤把局面寫成信纔誠恐有疑貪，最後以去後何須說二三收束。套用到健康，應理解為金錢往來最怕讒言、猜疑與貪念；在症狀變化、診療、休養與危險徵象上屬平。", "總論": "問總論時，詩中財帛相交莫信讒指出起因，去後何須說二三交代結果。兩者合看，表示金錢往來最怕讒言、猜疑與貪念。這項判為平，須以實際條件是否符合詩中轉機為準。", "婚姻": "財交守正不是抽象好壞，而是一個有條件的過程：信纔誠恐有疑貪顯示限制，寸心若得存中正顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為平。", "人際": "此項要從財帛相交莫信讒與寸心若得存中正的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是金錢往來最怕讒言、猜疑與貪念。因此評為平。", "感情": "第21籤把局面寫成信纔誠恐有疑貪，最後以去後何須說二三收束。套用到感情，應理解為金錢往來最怕讒言、猜疑與貪念；在雙方意願、互動品質與情緒安全上屬平。", "出行": "問出行時，詩中財帛相交莫信讒指出起因，去後何須說二三交代結果。兩者合看，表示金錢往來最怕讒言、猜疑與貪念。這項判為平，須以實際條件是否符合詩中轉機為準。", "家宅": "財交守正不是抽象好壞，而是一個有條件的過程：信纔誠恐有疑貪顯示限制，寸心若得存中正顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為平。", "修心建議": "此項要從財帛相交莫信讒與寸心若得存中正的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是金錢往來最怕讒言、猜疑與貪念。因此評為平。"}, "actionAdvice": ["先用財帛相交莫信讒確認現況，再以信纔誠恐有疑貪找出限制，觀察寸心若得存中正所示轉折，最後依去後何須說二三設定完成或停止條件。此籤的實際行動核心是：金錢往來最怕讒言、猜疑與貪念。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 22, "displayNo": "第22籤", "level": "偏弱", "title": "保生大帝第22籤", "poem": ["隻影迢迢路又疏", "不遭險恐也迷途", "臨行記得君有囑", "莫上高崗與險隅"], "story": "【避險守囑】詩文是直接的出行風險警告，並非抽象吉凶。", "classicMeaning": "", "plainMeaning": "第22籤主題為避險守囑。四句由隻影迢迢路又疏起筆，經不遭險恐也迷途與臨行記得君有囑推進，以莫上高崗與險隅收束。整體指出：獨行路疏，切勿走高岡險隅。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中隻影迢迢路又疏指出起因，莫上高崗與險隅交代結果。兩者合看，表示獨行路疏，切勿走高岡險隅。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "考試": "避險守囑不是抽象好壞，而是一個有條件的過程：不遭險恐也迷途顯示限制，臨行記得君有囑顯示轉折。對準備深度、評核時機與臨場表現而言，整體為偏弱。", "求財": "此項要從隻影迢迢路又疏與臨行記得君有囑的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是獨行路疏，切勿走高岡險隅。因此評為偏弱。", "失物": "第22籤把局面寫成不遭險恐也迷途，最後以莫上高崗與險隅收束。套用到失物，應理解為獨行路疏，切勿走高岡險隅；在遺失路徑、可追查線索與尋回時效上屬偏弱。", "健康": "問健康時，詩中隻影迢迢路又疏指出起因，莫上高崗與險隅交代結果。兩者合看，表示獨行路疏，切勿走高岡險隅。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "總論": "避險守囑不是抽象好壞，而是一個有條件的過程：不遭險恐也迷途顯示限制，臨行記得君有囑顯示轉折。對整體局勢、主要限制與轉機而言，整體為偏弱。", "婚姻": "此項要從隻影迢迢路又疏與臨行記得君有囑的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是獨行路疏，切勿走高岡險隅。因此評為偏弱。", "人際": "第22籤把局面寫成不遭險恐也迷途，最後以莫上高崗與險隅收束。套用到人際，應理解為獨行路疏，切勿走高岡險隅；在信任、貴人、小人與溝通界線上屬偏弱。", "感情": "問感情時，詩中隻影迢迢路又疏指出起因，莫上高崗與險隅交代結果。兩者合看，表示獨行路疏，切勿走高岡險隅。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "出行": "避險守囑不是抽象好壞，而是一個有條件的過程：不遭險恐也迷途顯示限制，臨行記得君有囑顯示轉折。對交通條件、方向、時機與人身安全而言，整體為凶。", "家宅": "此項要從隻影迢迢路又疏與臨行記得君有囑的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是獨行路疏，切勿走高岡險隅。因此評為偏弱。", "修心建議": "第22籤把局面寫成不遭險恐也迷途，最後以莫上高崗與險隅收束。套用到修心建議，應理解為獨行路疏，切勿走高岡險隅；在品格、節制、反省與實際改過上屬偏弱。"}, "actionAdvice": ["先用隻影迢迢路又疏確認現況，再以不遭險恐也迷途找出限制，觀察臨行記得君有囑所示轉折，最後依莫上高崗與險隅設定完成或停止條件。此籤的實際行動核心是：獨行路疏，切勿走高岡險隅。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 23, "displayNo": "第23籤", "level": "偏弱", "title": "保生大帝第23籤", "poem": ["整冠人道偷渠李", "納履傍觀謂摘瓜", "不如回卻家中坐", "無是無非莫管他"], "story": "【瓜田李下】古樂府《君子行》有瓜田不納履、李下不正冠之語，後用來表示主動避嫌。", "classicMeaning": "", "plainMeaning": "第23籤主題為瓜田李下。四句由整冠人道偷渠李起筆，經納履傍觀謂摘瓜與不如回卻家中坐推進，以無是無非莫管他收束。整體指出：即使無偷摘之意，也要避開容易被誤會的場合。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "瓜田李下不是抽象好壞，而是一個有條件的過程：納履傍觀謂摘瓜顯示限制，不如回卻家中坐顯示轉折。對職位、合作、執行條件與責任界線而言，整體為偏弱。", "考試": "此項要從整冠人道偷渠李與不如回卻家中坐的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是即使無偷摘之意，也要避開容易被誤會的場合。因此評為偏弱。", "求財": "第23籤把局面寫成納履傍觀謂摘瓜，最後以無是無非莫管他收束。套用到求財，應理解為即使無偷摘之意，也要避開容易被誤會的場合；在收入來源、交易成本、回收與風險上屬偏弱。", "失物": "問失物時，詩中整冠人道偷渠李指出起因，無是無非莫管他交代結果。兩者合看，表示即使無偷摘之意，也要避開容易被誤會的場合。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "健康": "瓜田李下不是抽象好壞，而是一個有條件的過程：納履傍觀謂摘瓜顯示限制，不如回卻家中坐顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為偏弱。", "總論": "此項要從整冠人道偷渠李與不如回卻家中坐的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是即使無偷摘之意，也要避開容易被誤會的場合。因此評為偏弱。", "婚姻": "第23籤把局面寫成納履傍觀謂摘瓜，最後以無是無非莫管他收束。套用到婚姻，應理解為即使無偷摘之意，也要避開容易被誤會的場合；在婚約、家庭共識、責任與長期相處上屬偏弱。", "人際": "問人際時，詩中整冠人道偷渠李指出起因，無是無非莫管他交代結果。兩者合看，表示即使無偷摘之意，也要避開容易被誤會的場合。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "感情": "瓜田李下不是抽象好壞，而是一個有條件的過程：納履傍觀謂摘瓜顯示限制，不如回卻家中坐顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為偏弱。", "出行": "此項要從整冠人道偷渠李與不如回卻家中坐的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是即使無偷摘之意，也要避開容易被誤會的場合。因此評為偏弱。", "家宅": "第23籤把局面寫成納履傍觀謂摘瓜，最後以無是無非莫管他收束。套用到家宅，應理解為即使無偷摘之意，也要避開容易被誤會的場合；在家庭安寧、居所、修繕與財產安排上屬偏弱。", "修心建議": "問修心建議時，詩中整冠人道偷渠李指出起因，無是無非莫管他交代結果。兩者合看，表示即使無偷摘之意，也要避開容易被誤會的場合。這項判為偏弱，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用整冠人道偷渠李確認現況，再以納履傍觀謂摘瓜找出限制，觀察不如回卻家中坐所示轉折，最後依無是無非莫管他設定完成或停止條件。此籤的實際行動核心是：即使無偷摘之意，也要避開容易被誤會的場合。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 24, "displayNo": "第24籤", "level": "吉", "title": "保生大帝第24籤", "poem": ["幸有仁人得盡扶", "進身何必苦躊躇", "欲求名利皆如意", "財帛自然應不虛"], "story": "【仁人扶進】仁人扶持是核心條件，名利財帛皆建立在可信協助上。", "classicMeaning": "", "plainMeaning": "第24籤主題為仁人扶進。四句由幸有仁人得盡扶起筆，經進身何必苦躊躇與欲求名利皆如意推進，以財帛自然應不虛收束。整體指出：得人相助後不必再猶豫。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從幸有仁人得盡扶與欲求名利皆如意的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是得人相助後不必再猶豫。因此評為大吉。", "考試": "第24籤把局面寫成進身何必苦躊躇，最後以財帛自然應不虛收束。套用到考試，應理解為得人相助後不必再猶豫；在準備深度、評核時機與臨場表現上屬大吉。", "求財": "問求財時，詩中幸有仁人得盡扶指出起因，財帛自然應不虛交代結果。兩者合看，表示得人相助後不必再猶豫。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "失物": "仁人扶進不是抽象好壞，而是一個有條件的過程：進身何必苦躊躇顯示限制，欲求名利皆如意顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為吉。", "健康": "此項要從幸有仁人得盡扶與欲求名利皆如意的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是得人相助後不必再猶豫。因此評為吉。", "總論": "第24籤把局面寫成進身何必苦躊躇，最後以財帛自然應不虛收束。套用到總論，應理解為得人相助後不必再猶豫；在整體局勢、主要限制與轉機上屬吉。", "婚姻": "問婚姻時，詩中幸有仁人得盡扶指出起因，財帛自然應不虛交代結果。兩者合看，表示得人相助後不必再猶豫。這項判為吉，須以實際條件是否符合詩中轉機為準。", "人際": "仁人扶進不是抽象好壞，而是一個有條件的過程：進身何必苦躊躇顯示限制，欲求名利皆如意顯示轉折。對信任、貴人、小人與溝通界線而言，整體為吉。", "感情": "此項要從幸有仁人得盡扶與欲求名利皆如意的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是得人相助後不必再猶豫。因此評為吉。", "出行": "第24籤把局面寫成進身何必苦躊躇，最後以財帛自然應不虛收束。套用到出行，應理解為得人相助後不必再猶豫；在交通條件、方向、時機與人身安全上屬吉。", "家宅": "問家宅時，詩中幸有仁人得盡扶指出起因，財帛自然應不虛交代結果。兩者合看，表示得人相助後不必再猶豫。這項判為吉，須以實際條件是否符合詩中轉機為準。", "修心建議": "仁人扶進不是抽象好壞，而是一個有條件的過程：進身何必苦躊躇顯示限制，欲求名利皆如意顯示轉折。對品格、節制、反省與實際改過而言，整體為吉。"}, "actionAdvice": ["先用幸有仁人得盡扶確認現況，再以進身何必苦躊躇找出限制，觀察欲求名利皆如意所示轉折，最後依財帛自然應不虛設定完成或停止條件。此籤的實際行動核心是：得人相助後不必再猶豫。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 25, "displayNo": "第25籤", "level": "吉", "title": "保生大帝第25籤", "poem": ["結契金蘭莫反仇", "朝中青紫不須求", "芸窗若肯相切磋", "一舉成名萬戶侯"], "story": "【金蘭切磋】金蘭比喻堅固友誼；青紫指高官服色；芸窗指書齋。", "classicMeaning": "", "plainMeaning": "第25籤主題為金蘭切磋。四句由結契金蘭莫反仇起筆，經朝中青紫不須求與芸窗若肯相切磋推進，以一舉成名萬戶侯收束。整體指出：同道互助與讀書切磋，比追逐官服更重要。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第25籤把局面寫成朝中青紫不須求，最後以一舉成名萬戶侯收束。套用到事業，應理解為同道互助與讀書切磋，比追逐官服更重要；在職位、合作、執行條件與責任界線上屬大吉。", "考試": "問考試時，詩中結契金蘭莫反仇指出起因，一舉成名萬戶侯交代結果。兩者合看，表示同道互助與讀書切磋，比追逐官服更重要。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "求財": "金蘭切磋不是抽象好壞，而是一個有條件的過程：朝中青紫不須求顯示限制，芸窗若肯相切磋顯示轉折。對收入來源、交易成本、回收與風險而言，整體為大吉。", "失物": "此項要從結契金蘭莫反仇與芸窗若肯相切磋的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是同道互助與讀書切磋，比追逐官服更重要。因此評為吉。", "健康": "第25籤把局面寫成朝中青紫不須求，最後以一舉成名萬戶侯收束。套用到健康，應理解為同道互助與讀書切磋，比追逐官服更重要；在症狀變化、診療、休養與危險徵象上屬吉。", "總論": "問總論時，詩中結契金蘭莫反仇指出起因，一舉成名萬戶侯交代結果。兩者合看，表示同道互助與讀書切磋，比追逐官服更重要。這項判為吉，須以實際條件是否符合詩中轉機為準。", "婚姻": "金蘭切磋不是抽象好壞，而是一個有條件的過程：朝中青紫不須求顯示限制，芸窗若肯相切磋顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為吉。", "人際": "此項要從結契金蘭莫反仇與芸窗若肯相切磋的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是同道互助與讀書切磋，比追逐官服更重要。因此評為吉。", "感情": "第25籤把局面寫成朝中青紫不須求，最後以一舉成名萬戶侯收束。套用到感情，應理解為同道互助與讀書切磋，比追逐官服更重要；在雙方意願、互動品質與情緒安全上屬吉。", "出行": "問出行時，詩中結契金蘭莫反仇指出起因，一舉成名萬戶侯交代結果。兩者合看，表示同道互助與讀書切磋，比追逐官服更重要。這項判為吉，須以實際條件是否符合詩中轉機為準。", "家宅": "金蘭切磋不是抽象好壞，而是一個有條件的過程：朝中青紫不須求顯示限制，芸窗若肯相切磋顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為吉。", "修心建議": "此項要從結契金蘭莫反仇與芸窗若肯相切磋的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是同道互助與讀書切磋，比追逐官服更重要。因此評為吉。"}, "actionAdvice": ["先用結契金蘭莫反仇確認現況，再以朝中青紫不須求找出限制，觀察芸窗若肯相切磋所示轉折，最後依一舉成名萬戶侯設定完成或停止條件。此籤的實際行動核心是：同道互助與讀書切磋，比追逐官服更重要。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 26, "displayNo": "第26籤", "level": "吉", "title": "保生大帝第26籤", "poem": ["誰言大海無珠寶", "只恐於人不為尋", "寶不負人人自負", "見之不取枉勞心"], "story": "【見寶須取】大海珠寶象徵深藏機會，寶不負人而人自負是責任轉向自身。", "classicMeaning": "", "plainMeaning": "第26籤主題為見寶須取。四句由誰言大海無珠寶起筆，經只恐於人不為尋與寶不負人人自負推進，以見之不取枉勞心收束。整體指出：資源存在，但必須主動尋找並及時把握。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中誰言大海無珠寶指出起因，見之不取枉勞心交代結果。兩者合看，表示資源存在，但必須主動尋找並及時把握。這項判為吉，須以實際條件是否符合詩中轉機為準。", "考試": "見寶須取不是抽象好壞，而是一個有條件的過程：只恐於人不為尋顯示限制，寶不負人人自負顯示轉折。對準備深度、評核時機與臨場表現而言，整體為吉。", "求財": "此項要從誰言大海無珠寶與寶不負人人自負的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是資源存在，但必須主動尋找並及時把握。因此評為吉。", "失物": "第26籤把局面寫成只恐於人不為尋，最後以見之不取枉勞心收束。套用到失物，應理解為資源存在，但必須主動尋找並及時把握；在遺失路徑、可追查線索與尋回時效上屬吉。", "健康": "問健康時，詩中誰言大海無珠寶指出起因，見之不取枉勞心交代結果。兩者合看，表示資源存在，但必須主動尋找並及時把握。這項判為吉，須以實際條件是否符合詩中轉機為準。", "總論": "見寶須取不是抽象好壞，而是一個有條件的過程：只恐於人不為尋顯示限制，寶不負人人自負顯示轉折。對整體局勢、主要限制與轉機而言，整體為吉。", "婚姻": "此項要從誰言大海無珠寶與寶不負人人自負的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是資源存在，但必須主動尋找並及時把握。因此評為吉。", "人際": "第26籤把局面寫成只恐於人不為尋，最後以見之不取枉勞心收束。套用到人際，應理解為資源存在，但必須主動尋找並及時把握；在信任、貴人、小人與溝通界線上屬吉。", "感情": "問感情時，詩中誰言大海無珠寶指出起因，見之不取枉勞心交代結果。兩者合看，表示資源存在，但必須主動尋找並及時把握。這項判為吉，須以實際條件是否符合詩中轉機為準。", "出行": "見寶須取不是抽象好壞，而是一個有條件的過程：只恐於人不為尋顯示限制，寶不負人人自負顯示轉折。對交通條件、方向、時機與人身安全而言，整體為吉。", "家宅": "此項要從誰言大海無珠寶與寶不負人人自負的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是資源存在，但必須主動尋找並及時把握。因此評為吉。", "修心建議": "第26籤把局面寫成只恐於人不為尋，最後以見之不取枉勞心收束。套用到修心建議，應理解為資源存在，但必須主動尋找並及時把握；在品格、節制、反省與實際改過上屬吉。"}, "actionAdvice": ["先用誰言大海無珠寶確認現況，再以只恐於人不為尋找出限制，觀察寶不負人人自負所示轉折，最後依見之不取枉勞心設定完成或停止條件。此籤的實際行動核心是：資源存在，但必須主動尋找並及時把握。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 27, "displayNo": "第27籤", "level": "吉", "title": "保生大帝第27籤", "poem": ["一文欲換兩千文", "誰道斯言是妄云", "富貴榮華天與汝", "歸期喜鵲噪紛紛"], "story": "【小本大利】一文換兩千文是誇張比例，用來表達財運放大。", "classicMeaning": "", "plainMeaning": "第27籤主題為小本大利。四句由一文欲換兩千文起筆，經誰道斯言是妄云與富貴榮華天與汝推進，以歸期喜鵲噪紛紛收束。整體指出：高報酬之象很強，仍須防把吉語當成無風險保證。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "小本大利不是抽象好壞，而是一個有條件的過程：誰道斯言是妄云顯示限制，富貴榮華天與汝顯示轉折。對職位、合作、執行條件與責任界線而言，整體為大吉。", "考試": "此項要從一文欲換兩千文與富貴榮華天與汝的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是高報酬之象很強，仍須防把吉語當成無風險保證。因此評為大吉。", "求財": "第27籤把局面寫成誰道斯言是妄云，最後以歸期喜鵲噪紛紛收束。套用到求財，應理解為高報酬之象很強，仍須防把吉語當成無風險保證；在收入來源、交易成本、回收與風險上屬大吉。", "失物": "問失物時，詩中一文欲換兩千文指出起因，歸期喜鵲噪紛紛交代結果。兩者合看，表示高報酬之象很強，仍須防把吉語當成無風險保證。這項判為吉，須以實際條件是否符合詩中轉機為準。", "健康": "小本大利不是抽象好壞，而是一個有條件的過程：誰道斯言是妄云顯示限制，富貴榮華天與汝顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為吉。", "總論": "此項要從一文欲換兩千文與富貴榮華天與汝的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是高報酬之象很強，仍須防把吉語當成無風險保證。因此評為吉。", "婚姻": "第27籤把局面寫成誰道斯言是妄云，最後以歸期喜鵲噪紛紛收束。套用到婚姻，應理解為高報酬之象很強，仍須防把吉語當成無風險保證；在婚約、家庭共識、責任與長期相處上屬吉。", "人際": "問人際時，詩中一文欲換兩千文指出起因，歸期喜鵲噪紛紛交代結果。兩者合看，表示高報酬之象很強，仍須防把吉語當成無風險保證。這項判為吉，須以實際條件是否符合詩中轉機為準。", "感情": "小本大利不是抽象好壞，而是一個有條件的過程：誰道斯言是妄云顯示限制，富貴榮華天與汝顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為吉。", "出行": "此項要從一文欲換兩千文與富貴榮華天與汝的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是高報酬之象很強，仍須防把吉語當成無風險保證。因此評為吉。", "家宅": "第27籤把局面寫成誰道斯言是妄云，最後以歸期喜鵲噪紛紛收束。套用到家宅，應理解為高報酬之象很強，仍須防把吉語當成無風險保證；在家庭安寧、居所、修繕與財產安排上屬吉。", "修心建議": "問修心建議時，詩中一文欲換兩千文指出起因，歸期喜鵲噪紛紛交代結果。兩者合看，表示高報酬之象很強，仍須防把吉語當成無風險保證。這項判為吉，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用一文欲換兩千文確認現況，再以誰道斯言是妄云找出限制，觀察富貴榮華天與汝所示轉折，最後依歸期喜鵲噪紛紛設定完成或停止條件。此籤的實際行動核心是：高報酬之象很強，仍須防把吉語當成無風險保證。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 28, "displayNo": "第28籤", "level": "吉", "title": "保生大帝第28籤", "poem": ["乍聞喜鵲噪簷聲", "謀望欣然自稱情", "最是行藏堪愛處", "閉門家內有人迎"], "story": "【鵲報人迎】喜鵲報喜是漢文化常見吉兆意象。", "classicMeaning": "", "plainMeaning": "第28籤主題為鵲報人迎。四句由乍聞喜鵲噪簷聲起筆，經謀望欣然自稱情與最是行藏堪愛處推進，以閉門家內有人迎收束。整體指出：喜訊已近，家內有人接應。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從乍聞喜鵲噪簷聲與最是行藏堪愛處的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是喜訊已近，家內有人接應。因此評為吉。", "考試": "第28籤把局面寫成謀望欣然自稱情，最後以閉門家內有人迎收束。套用到考試，應理解為喜訊已近，家內有人接應；在準備深度、評核時機與臨場表現上屬吉。", "求財": "問求財時，詩中乍聞喜鵲噪簷聲指出起因，閉門家內有人迎交代結果。兩者合看，表示喜訊已近，家內有人接應。這項判為吉，須以實際條件是否符合詩中轉機為準。", "失物": "鵲報人迎不是抽象好壞，而是一個有條件的過程：謀望欣然自稱情顯示限制，最是行藏堪愛處顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為吉。", "健康": "此項要從乍聞喜鵲噪簷聲與最是行藏堪愛處的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是喜訊已近，家內有人接應。因此評為吉。", "總論": "第28籤把局面寫成謀望欣然自稱情，最後以閉門家內有人迎收束。套用到總論，應理解為喜訊已近，家內有人接應；在整體局勢、主要限制與轉機上屬吉。", "婚姻": "問婚姻時，詩中乍聞喜鵲噪簷聲指出起因，閉門家內有人迎交代結果。兩者合看，表示喜訊已近，家內有人接應。這項判為吉，須以實際條件是否符合詩中轉機為準。", "人際": "鵲報人迎不是抽象好壞，而是一個有條件的過程：謀望欣然自稱情顯示限制，最是行藏堪愛處顯示轉折。對信任、貴人、小人與溝通界線而言，整體為吉。", "感情": "此項要從乍聞喜鵲噪簷聲與最是行藏堪愛處的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是喜訊已近，家內有人接應。因此評為吉。", "出行": "第28籤把局面寫成謀望欣然自稱情，最後以閉門家內有人迎收束。套用到出行，應理解為喜訊已近，家內有人接應；在交通條件、方向、時機與人身安全上屬吉。", "家宅": "問家宅時，詩中乍聞喜鵲噪簷聲指出起因，閉門家內有人迎交代結果。兩者合看，表示喜訊已近，家內有人接應。這項判為吉，須以實際條件是否符合詩中轉機為準。", "修心建議": "鵲報人迎不是抽象好壞，而是一個有條件的過程：謀望欣然自稱情顯示限制，最是行藏堪愛處顯示轉折。對品格、節制、反省與實際改過而言，整體為吉。"}, "actionAdvice": ["先用乍聞喜鵲噪簷聲確認現況，再以謀望欣然自稱情找出限制，觀察最是行藏堪愛處所示轉折，最後依閉門家內有人迎設定完成或停止條件。此籤的實際行動核心是：喜訊已近，家內有人接應。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 29, "displayNo": "第29籤", "level": "吉", "title": "保生大帝第29籤", "poem": ["伊尹耘耕於有莘", "太公垂釣渭江濱", "兩人久屈林泉下", "一旦為君輔弼臣"], "story": "【久屈得用】伊尹由有莘起而輔商湯；姜太公垂釣渭濱而遇周文王。籤詩取兩人久困後獲重用的共同結構。", "classicMeaning": "", "plainMeaning": "第29籤主題為久屈得用。四句由伊尹耘耕於有莘起筆，經太公垂釣渭江濱與兩人久屈林泉下推進，以一旦為君輔弼臣收束。整體指出：有才者長久沉潛，終逢明主而被任用。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第29籤把局面寫成太公垂釣渭江濱，最後以一旦為君輔弼臣收束。套用到事業，應理解為有才者長久沉潛，終逢明主而被任用；在職位、合作、執行條件與責任界線上屬大吉。", "考試": "問考試時，詩中伊尹耘耕於有莘指出起因，一旦為君輔弼臣交代結果。兩者合看，表示有才者長久沉潛，終逢明主而被任用。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "求財": "久屈得用不是抽象好壞，而是一個有條件的過程：太公垂釣渭江濱顯示限制，兩人久屈林泉下顯示轉折。對收入來源、交易成本、回收與風險而言，整體為大吉。", "失物": "此項要從伊尹耘耕於有莘與兩人久屈林泉下的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是有才者長久沉潛，終逢明主而被任用。因此評為吉。", "健康": "第29籤把局面寫成太公垂釣渭江濱，最後以一旦為君輔弼臣收束。套用到健康，應理解為有才者長久沉潛，終逢明主而被任用；在症狀變化、診療、休養與危險徵象上屬吉。", "總論": "問總論時，詩中伊尹耘耕於有莘指出起因，一旦為君輔弼臣交代結果。兩者合看，表示有才者長久沉潛，終逢明主而被任用。這項判為吉，須以實際條件是否符合詩中轉機為準。", "婚姻": "久屈得用不是抽象好壞，而是一個有條件的過程：太公垂釣渭江濱顯示限制，兩人久屈林泉下顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為吉。", "人際": "此項要從伊尹耘耕於有莘與兩人久屈林泉下的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是有才者長久沉潛，終逢明主而被任用。因此評為吉。", "感情": "第29籤把局面寫成太公垂釣渭江濱，最後以一旦為君輔弼臣收束。套用到感情，應理解為有才者長久沉潛，終逢明主而被任用；在雙方意願、互動品質與情緒安全上屬吉。", "出行": "問出行時，詩中伊尹耘耕於有莘指出起因，一旦為君輔弼臣交代結果。兩者合看，表示有才者長久沉潛，終逢明主而被任用。這項判為吉，須以實際條件是否符合詩中轉機為準。", "家宅": "久屈得用不是抽象好壞，而是一個有條件的過程：太公垂釣渭江濱顯示限制，兩人久屈林泉下顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為吉。", "修心建議": "此項要從伊尹耘耕於有莘與兩人久屈林泉下的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是有才者長久沉潛，終逢明主而被任用。因此評為吉。"}, "actionAdvice": ["先用伊尹耘耕於有莘確認現況，再以太公垂釣渭江濱找出限制，觀察兩人久屈林泉下所示轉折，最後依一旦為君輔弼臣設定完成或停止條件。此籤的實際行動核心是：有才者長久沉潛，終逢明主而被任用。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 30, "displayNo": "第30籤", "level": "偏弱", "title": "保生大帝第30籤", "poem": ["鐵船渡海最沈重", "紙屋居人豈可容", "能得脫離雙險道", "蓮花火裡水溶溶"], "story": "【雙險求脫】鐵船、紙屋皆不合常理；火中蓮花則象徵逆境中的清淨與生機。", "classicMeaning": "", "plainMeaning": "第30籤主題為雙險求脫。四句由鐵船渡海最沈重起筆，經紙屋居人豈可容與能得脫離雙險道推進，以蓮花火裡水溶溶收束。整體指出：所處條件彼此矛盾，先脫險才能談成果。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中鐵船渡海最沈重指出起因，蓮花火裡水溶溶交代結果。兩者合看，表示所處條件彼此矛盾，先脫險才能談成果。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "考試": "雙險求脫不是抽象好壞，而是一個有條件的過程：紙屋居人豈可容顯示限制，能得脫離雙險道顯示轉折。對準備深度、評核時機與臨場表現而言，整體為偏弱。", "求財": "此項要從鐵船渡海最沈重與能得脫離雙險道的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是所處條件彼此矛盾，先脫險才能談成果。因此評為偏弱。", "失物": "第30籤把局面寫成紙屋居人豈可容，最後以蓮花火裡水溶溶收束。套用到失物，應理解為所處條件彼此矛盾，先脫險才能談成果；在遺失路徑、可追查線索與尋回時效上屬偏弱。", "健康": "問健康時，詩中鐵船渡海最沈重指出起因，蓮花火裡水溶溶交代結果。兩者合看，表示所處條件彼此矛盾，先脫險才能談成果。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "總論": "雙險求脫不是抽象好壞，而是一個有條件的過程：紙屋居人豈可容顯示限制，能得脫離雙險道顯示轉折。對整體局勢、主要限制與轉機而言，整體為偏弱。", "婚姻": "此項要從鐵船渡海最沈重與能得脫離雙險道的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是所處條件彼此矛盾，先脫險才能談成果。因此評為偏弱。", "人際": "第30籤把局面寫成紙屋居人豈可容，最後以蓮花火裡水溶溶收束。套用到人際，應理解為所處條件彼此矛盾，先脫險才能談成果；在信任、貴人、小人與溝通界線上屬偏弱。", "感情": "問感情時，詩中鐵船渡海最沈重指出起因，蓮花火裡水溶溶交代結果。兩者合看，表示所處條件彼此矛盾，先脫險才能談成果。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "出行": "雙險求脫不是抽象好壞，而是一個有條件的過程：紙屋居人豈可容顯示限制，能得脫離雙險道顯示轉折。對交通條件、方向、時機與人身安全而言，整體為偏弱。", "家宅": "此項要從鐵船渡海最沈重與能得脫離雙險道的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是所處條件彼此矛盾，先脫險才能談成果。因此評為偏弱。", "修心建議": "第30籤把局面寫成紙屋居人豈可容，最後以蓮花火裡水溶溶收束。套用到修心建議，應理解為所處條件彼此矛盾，先脫險才能談成果；在品格、節制、反省與實際改過上屬偏弱。"}, "actionAdvice": ["先用鐵船渡海最沈重確認現況，再以紙屋居人豈可容找出限制，觀察能得脫離雙險道所示轉折，最後依蓮花火裡水溶溶設定完成或停止條件。此籤的實際行動核心是：所處條件彼此矛盾，先脫險才能談成果。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 31, "displayNo": "第31籤", "level": "吉", "title": "保生大帝第31籤", "poem": ["自求福德自天申", "福分未真寧作真", "運動行藏皆合意", "一番喜氣一番新"], "story": "【福由自求】自求福德呼應積善修身的倫理，不宜理解成只靠外力賜福。", "classicMeaning": "", "plainMeaning": "第31籤主題為福由自求。四句由自求福德自天申起筆，經福分未真寧作真與運動行藏皆合意推進，以一番喜氣一番新收束。整體指出：福德需以自身行動承接，行藏漸合意。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "福由自求不是抽象好壞，而是一個有條件的過程：福分未真寧作真顯示限制，運動行藏皆合意顯示轉折。對職位、合作、執行條件與責任界線而言，整體為吉。", "考試": "此項要從自求福德自天申與運動行藏皆合意的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是福德需以自身行動承接，行藏漸合意。因此評為吉。", "求財": "第31籤把局面寫成福分未真寧作真，最後以一番喜氣一番新收束。套用到求財，應理解為福德需以自身行動承接，行藏漸合意；在收入來源、交易成本、回收與風險上屬吉。", "失物": "問失物時，詩中自求福德自天申指出起因，一番喜氣一番新交代結果。兩者合看，表示福德需以自身行動承接，行藏漸合意。這項判為吉，須以實際條件是否符合詩中轉機為準。", "健康": "福由自求不是抽象好壞，而是一個有條件的過程：福分未真寧作真顯示限制，運動行藏皆合意顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為吉。", "總論": "此項要從自求福德自天申與運動行藏皆合意的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是福德需以自身行動承接，行藏漸合意。因此評為吉。", "婚姻": "第31籤把局面寫成福分未真寧作真，最後以一番喜氣一番新收束。套用到婚姻，應理解為福德需以自身行動承接，行藏漸合意；在婚約、家庭共識、責任與長期相處上屬吉。", "人際": "問人際時，詩中自求福德自天申指出起因，一番喜氣一番新交代結果。兩者合看，表示福德需以自身行動承接，行藏漸合意。這項判為吉，須以實際條件是否符合詩中轉機為準。", "感情": "福由自求不是抽象好壞，而是一個有條件的過程：福分未真寧作真顯示限制，運動行藏皆合意顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為吉。", "出行": "此項要從自求福德自天申與運動行藏皆合意的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是福德需以自身行動承接，行藏漸合意。因此評為吉。", "家宅": "第31籤把局面寫成福分未真寧作真，最後以一番喜氣一番新收束。套用到家宅，應理解為福德需以自身行動承接，行藏漸合意；在家庭安寧、居所、修繕與財產安排上屬吉。", "修心建議": "問修心建議時，詩中自求福德自天申指出起因，一番喜氣一番新交代結果。兩者合看，表示福德需以自身行動承接，行藏漸合意。這項判為吉，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用自求福德自天申確認現況，再以福分未真寧作真找出限制，觀察運動行藏皆合意所示轉折，最後依一番喜氣一番新設定完成或停止條件。此籤的實際行動核心是：福德需以自身行動承接，行藏漸合意。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 32, "displayNo": "第32籤", "level": "吉", "title": "保生大帝第32籤", "poem": ["一杯清水救斯民", "何必區區別問津", "富貴榮華天必與", "無仇無慮在君身"], "story": "【清水濟民】一杯清水重在心意與實效，不在形式鋪張。", "classicMeaning": "", "plainMeaning": "第32籤主題為清水濟民。四句由一杯清水救斯民起筆，經何必區區別問津與富貴榮華天必與推進，以無仇無慮在君身收束。整體指出：以簡單真誠之心救助他人，反得無憂富貴。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從一杯清水救斯民與富貴榮華天必與的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是以簡單真誠之心救助他人，反得無憂富貴。因此評為大吉。", "考試": "第32籤把局面寫成何必區區別問津，最後以無仇無慮在君身收束。套用到考試，應理解為以簡單真誠之心救助他人，反得無憂富貴；在準備深度、評核時機與臨場表現上屬大吉。", "求財": "問求財時，詩中一杯清水救斯民指出起因，無仇無慮在君身交代結果。兩者合看，表示以簡單真誠之心救助他人，反得無憂富貴。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "失物": "清水濟民不是抽象好壞，而是一個有條件的過程：何必區區別問津顯示限制，富貴榮華天必與顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為吉。", "健康": "此項要從一杯清水救斯民與富貴榮華天必與的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是以簡單真誠之心救助他人，反得無憂富貴。因此評為吉。", "總論": "第32籤把局面寫成何必區區別問津，最後以無仇無慮在君身收束。套用到總論，應理解為以簡單真誠之心救助他人，反得無憂富貴；在整體局勢、主要限制與轉機上屬吉。", "婚姻": "問婚姻時，詩中一杯清水救斯民指出起因，無仇無慮在君身交代結果。兩者合看，表示以簡單真誠之心救助他人，反得無憂富貴。這項判為吉，須以實際條件是否符合詩中轉機為準。", "人際": "清水濟民不是抽象好壞，而是一個有條件的過程：何必區區別問津顯示限制，富貴榮華天必與顯示轉折。對信任、貴人、小人與溝通界線而言，整體為吉。", "感情": "此項要從一杯清水救斯民與富貴榮華天必與的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是以簡單真誠之心救助他人，反得無憂富貴。因此評為吉。", "出行": "第32籤把局面寫成何必區區別問津，最後以無仇無慮在君身收束。套用到出行，應理解為以簡單真誠之心救助他人，反得無憂富貴；在交通條件、方向、時機與人身安全上屬吉。", "家宅": "問家宅時，詩中一杯清水救斯民指出起因，無仇無慮在君身交代結果。兩者合看，表示以簡單真誠之心救助他人，反得無憂富貴。這項判為吉，須以實際條件是否符合詩中轉機為準。", "修心建議": "清水濟民不是抽象好壞，而是一個有條件的過程：何必區區別問津顯示限制，富貴榮華天必與顯示轉折。對品格、節制、反省與實際改過而言，整體為吉。"}, "actionAdvice": ["先用一杯清水救斯民確認現況，再以何必區區別問津找出限制，觀察富貴榮華天必與所示轉折，最後依無仇無慮在君身設定完成或停止條件。此籤的實際行動核心是：以簡單真誠之心救助他人，反得無憂富貴。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 33, "displayNo": "第33籤", "level": "吉", "title": "保生大帝第33籤", "poem": ["枯木逢春再發花", "秋蟾皎潔絕雲霞", "兩般消息皆分曉", "也知不久到吾家"], "story": "【春回月明】枯木逢春與秋蟾無雲，分別象徵生命復甦與資訊清楚。", "classicMeaning": "", "plainMeaning": "第33籤主題為春回月明。四句由枯木逢春再發花起筆，經秋蟾皎潔絕雲霞與兩般消息皆分曉推進，以也知不久到吾家收束。整體指出：兩項消息皆趨明朗，復甦與歸期不遠。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第33籤把局面寫成秋蟾皎潔絕雲霞，最後以也知不久到吾家收束。套用到事業，應理解為兩項消息皆趨明朗，復甦與歸期不遠；在職位、合作、執行條件與責任界線上屬吉。", "考試": "問考試時，詩中枯木逢春再發花指出起因，也知不久到吾家交代結果。兩者合看，表示兩項消息皆趨明朗，復甦與歸期不遠。這項判為吉，須以實際條件是否符合詩中轉機為準。", "求財": "春回月明不是抽象好壞，而是一個有條件的過程：秋蟾皎潔絕雲霞顯示限制，兩般消息皆分曉顯示轉折。對收入來源、交易成本、回收與風險而言，整體為吉。", "失物": "此項要從枯木逢春再發花與兩般消息皆分曉的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是兩項消息皆趨明朗，復甦與歸期不遠。因此評為吉。", "健康": "第33籤把局面寫成秋蟾皎潔絕雲霞，最後以也知不久到吾家收束。套用到健康，應理解為兩項消息皆趨明朗，復甦與歸期不遠；在症狀變化、診療、休養與危險徵象上屬吉。", "總論": "問總論時，詩中枯木逢春再發花指出起因，也知不久到吾家交代結果。兩者合看，表示兩項消息皆趨明朗，復甦與歸期不遠。這項判為吉，須以實際條件是否符合詩中轉機為準。", "婚姻": "春回月明不是抽象好壞，而是一個有條件的過程：秋蟾皎潔絕雲霞顯示限制，兩般消息皆分曉顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為吉。", "人際": "此項要從枯木逢春再發花與兩般消息皆分曉的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是兩項消息皆趨明朗，復甦與歸期不遠。因此評為吉。", "感情": "第33籤把局面寫成秋蟾皎潔絕雲霞，最後以也知不久到吾家收束。套用到感情，應理解為兩項消息皆趨明朗，復甦與歸期不遠；在雙方意願、互動品質與情緒安全上屬吉。", "出行": "問出行時，詩中枯木逢春再發花指出起因，也知不久到吾家交代結果。兩者合看，表示兩項消息皆趨明朗，復甦與歸期不遠。這項判為吉，須以實際條件是否符合詩中轉機為準。", "家宅": "春回月明不是抽象好壞，而是一個有條件的過程：秋蟾皎潔絕雲霞顯示限制，兩般消息皆分曉顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為吉。", "修心建議": "此項要從枯木逢春再發花與兩般消息皆分曉的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是兩項消息皆趨明朗，復甦與歸期不遠。因此評為吉。"}, "actionAdvice": ["先用枯木逢春再發花確認現況，再以秋蟾皎潔絕雲霞找出限制，觀察兩般消息皆分曉所示轉折，最後依也知不久到吾家設定完成或停止條件。此籤的實際行動核心是：兩項消息皆趨明朗，復甦與歸期不遠。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 34, "displayNo": "第34籤", "level": "偏弱", "title": "保生大帝第34籤", "poem": ["巨川欲渡無舟楫", "大廈將成少棟樑", "自是天時無便利", "放心靜坐細思量"], "story": "【缺舟少樑】渡巨川需舟楫、成大廈需棟樑，是條件不足的經典譬喻。", "classicMeaning": "", "plainMeaning": "第34籤主題為缺舟少樑。四句由巨川欲渡無舟楫起筆，經大廈將成少棟樑與自是天時無便利推進，以放心靜坐細思量收束。整體指出：目標大而關鍵資源不足，天時也不便利。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中巨川欲渡無舟楫指出起因，放心靜坐細思量交代結果。兩者合看，表示目標大而關鍵資源不足，天時也不便利。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "考試": "缺舟少樑不是抽象好壞，而是一個有條件的過程：大廈將成少棟樑顯示限制，自是天時無便利顯示轉折。對準備深度、評核時機與臨場表現而言，整體為偏弱。", "求財": "此項要從巨川欲渡無舟楫與自是天時無便利的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是目標大而關鍵資源不足，天時也不便利。因此評為偏弱。", "失物": "第34籤把局面寫成大廈將成少棟樑，最後以放心靜坐細思量收束。套用到失物，應理解為目標大而關鍵資源不足，天時也不便利；在遺失路徑、可追查線索與尋回時效上屬偏弱。", "健康": "問健康時，詩中巨川欲渡無舟楫指出起因，放心靜坐細思量交代結果。兩者合看，表示目標大而關鍵資源不足，天時也不便利。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "總論": "缺舟少樑不是抽象好壞，而是一個有條件的過程：大廈將成少棟樑顯示限制，自是天時無便利顯示轉折。對整體局勢、主要限制與轉機而言，整體為偏弱。", "婚姻": "此項要從巨川欲渡無舟楫與自是天時無便利的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是目標大而關鍵資源不足，天時也不便利。因此評為偏弱。", "人際": "第34籤把局面寫成大廈將成少棟樑，最後以放心靜坐細思量收束。套用到人際，應理解為目標大而關鍵資源不足，天時也不便利；在信任、貴人、小人與溝通界線上屬偏弱。", "感情": "問感情時，詩中巨川欲渡無舟楫指出起因，放心靜坐細思量交代結果。兩者合看，表示目標大而關鍵資源不足，天時也不便利。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "出行": "缺舟少樑不是抽象好壞，而是一個有條件的過程：大廈將成少棟樑顯示限制，自是天時無便利顯示轉折。對交通條件、方向、時機與人身安全而言，整體為偏弱。", "家宅": "此項要從巨川欲渡無舟楫與自是天時無便利的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是目標大而關鍵資源不足，天時也不便利。因此評為偏弱。", "修心建議": "第34籤把局面寫成大廈將成少棟樑，最後以放心靜坐細思量收束。套用到修心建議，應理解為目標大而關鍵資源不足，天時也不便利；在品格、節制、反省與實際改過上屬偏弱。"}, "actionAdvice": ["先用巨川欲渡無舟楫確認現況，再以大廈將成少棟樑找出限制，觀察自是天時無便利所示轉折，最後依放心靜坐細思量設定完成或停止條件。此籤的實際行動核心是：目標大而關鍵資源不足，天時也不便利。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 35, "displayNo": "第35籤", "level": "吉", "title": "保生大帝第35籤", "poem": ["牡丹驟雨壓欹斜", "皎月揚輝雲莫遮", "雲豈不時遮月色", "雨無常壓有名花"], "story": "【名花不久壓】驟雨壓牡丹、雲遮明月皆為暫時外力遮蔽。", "classicMeaning": "", "plainMeaning": "第35籤主題為名花不久壓。四句由牡丹驟雨壓欹斜起筆，經皎月揚輝雲莫遮與雲豈不時遮月色推進，以雨無常壓有名花收束。整體指出：眼前受挫只是短暫，真正價值仍能復明。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "名花不久壓不是抽象好壞，而是一個有條件的過程：皎月揚輝雲莫遮顯示限制，雲豈不時遮月色顯示轉折。對職位、合作、執行條件與責任界線而言，整體為吉。", "考試": "此項要從牡丹驟雨壓欹斜與雲豈不時遮月色的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是眼前受挫只是短暫，真正價值仍能復明。因此評為吉。", "求財": "第35籤把局面寫成皎月揚輝雲莫遮，最後以雨無常壓有名花收束。套用到求財，應理解為眼前受挫只是短暫，真正價值仍能復明；在收入來源、交易成本、回收與風險上屬吉。", "失物": "問失物時，詩中牡丹驟雨壓欹斜指出起因，雨無常壓有名花交代結果。兩者合看，表示眼前受挫只是短暫，真正價值仍能復明。這項判為吉，須以實際條件是否符合詩中轉機為準。", "健康": "名花不久壓不是抽象好壞，而是一個有條件的過程：皎月揚輝雲莫遮顯示限制，雲豈不時遮月色顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為吉。", "總論": "此項要從牡丹驟雨壓欹斜與雲豈不時遮月色的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是眼前受挫只是短暫，真正價值仍能復明。因此評為吉。", "婚姻": "第35籤把局面寫成皎月揚輝雲莫遮，最後以雨無常壓有名花收束。套用到婚姻，應理解為眼前受挫只是短暫，真正價值仍能復明；在婚約、家庭共識、責任與長期相處上屬吉。", "人際": "問人際時，詩中牡丹驟雨壓欹斜指出起因，雨無常壓有名花交代結果。兩者合看，表示眼前受挫只是短暫，真正價值仍能復明。這項判為吉，須以實際條件是否符合詩中轉機為準。", "感情": "名花不久壓不是抽象好壞，而是一個有條件的過程：皎月揚輝雲莫遮顯示限制，雲豈不時遮月色顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為吉。", "出行": "此項要從牡丹驟雨壓欹斜與雲豈不時遮月色的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是眼前受挫只是短暫，真正價值仍能復明。因此評為吉。", "家宅": "第35籤把局面寫成皎月揚輝雲莫遮，最後以雨無常壓有名花收束。套用到家宅，應理解為眼前受挫只是短暫，真正價值仍能復明；在家庭安寧、居所、修繕與財產安排上屬吉。", "修心建議": "問修心建議時，詩中牡丹驟雨壓欹斜指出起因，雨無常壓有名花交代結果。兩者合看，表示眼前受挫只是短暫，真正價值仍能復明。這項判為吉，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用牡丹驟雨壓欹斜確認現況，再以皎月揚輝雲莫遮找出限制，觀察雲豈不時遮月色所示轉折，最後依雨無常壓有名花設定完成或停止條件。此籤的實際行動核心是：眼前受挫只是短暫，真正價值仍能復明。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 36, "displayNo": "第36籤", "level": "吉", "title": "保生大帝第36籤", "poem": ["花有重開再月圓", "家中幸有得媒賢", "他人欲起心殘害", "卻被貴人發制先"], "story": "【重開再圓】花重開、月再圓是復合與修復的明確象徵。", "classicMeaning": "", "plainMeaning": "第36籤主題為重開再圓。四句由花有重開再月圓起筆，經家中幸有得媒賢與他人欲起心殘害推進，以卻被貴人發制先收束。整體指出：失而復得，且有媒賢與貴人先制小人。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從花有重開再月圓與他人欲起心殘害的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是失而復得，且有媒賢與貴人先制小人。因此評為大吉。", "考試": "第36籤把局面寫成家中幸有得媒賢，最後以卻被貴人發制先收束。套用到考試，應理解為失而復得，且有媒賢與貴人先制小人；在準備深度、評核時機與臨場表現上屬大吉。", "求財": "問求財時，詩中花有重開再月圓指出起因，卻被貴人發制先交代結果。兩者合看，表示失而復得，且有媒賢與貴人先制小人。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "失物": "重開再圓不是抽象好壞，而是一個有條件的過程：家中幸有得媒賢顯示限制，他人欲起心殘害顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為吉。", "健康": "此項要從花有重開再月圓與他人欲起心殘害的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是失而復得，且有媒賢與貴人先制小人。因此評為吉。", "總論": "第36籤把局面寫成家中幸有得媒賢，最後以卻被貴人發制先收束。套用到總論，應理解為失而復得，且有媒賢與貴人先制小人；在整體局勢、主要限制與轉機上屬吉。", "婚姻": "問婚姻時，詩中花有重開再月圓指出起因，卻被貴人發制先交代結果。兩者合看，表示失而復得，且有媒賢與貴人先制小人。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "人際": "重開再圓不是抽象好壞，而是一個有條件的過程：家中幸有得媒賢顯示限制，他人欲起心殘害顯示轉折。對信任、貴人、小人與溝通界線而言，整體為吉。", "感情": "此項要從花有重開再月圓與他人欲起心殘害的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是失而復得，且有媒賢與貴人先制小人。因此評為大吉。", "出行": "第36籤把局面寫成家中幸有得媒賢，最後以卻被貴人發制先收束。套用到出行，應理解為失而復得，且有媒賢與貴人先制小人；在交通條件、方向、時機與人身安全上屬吉。", "家宅": "問家宅時，詩中花有重開再月圓指出起因，卻被貴人發制先交代結果。兩者合看，表示失而復得，且有媒賢與貴人先制小人。這項判為吉，須以實際條件是否符合詩中轉機為準。", "修心建議": "重開再圓不是抽象好壞，而是一個有條件的過程：家中幸有得媒賢顯示限制，他人欲起心殘害顯示轉折。對品格、節制、反省與實際改過而言，整體為吉。"}, "actionAdvice": ["先用花有重開再月圓確認現況，再以家中幸有得媒賢找出限制，觀察他人欲起心殘害所示轉折，最後依卻被貴人發制先設定完成或停止條件。此籤的實際行動核心是：失而復得，且有媒賢與貴人先制小人。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 37, "displayNo": "第37籤", "level": "吉", "title": "保生大帝第37籤", "poem": ["匣中寶鏡掛高臺", "今日欣逢匣正開", "不管人間分萬類", "一時廣照在東來"], "story": "【寶鏡開匣】寶鏡開匣象徵才能解除封存、評價轉明。", "classicMeaning": "", "plainMeaning": "第37籤主題為寶鏡開匣。四句由匣中寶鏡掛高臺起筆，經今日欣逢匣正開與不管人間分萬類推進，以一時廣照在東來收束。整體指出：被遮藏的能力或真相開始普照。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第37籤把局面寫成今日欣逢匣正開，最後以一時廣照在東來收束。套用到事業，應理解為被遮藏的能力或真相開始普照；在職位、合作、執行條件與責任界線上屬吉。", "考試": "問考試時，詩中匣中寶鏡掛高臺指出起因，一時廣照在東來交代結果。兩者合看，表示被遮藏的能力或真相開始普照。這項判為吉，須以實際條件是否符合詩中轉機為準。", "求財": "寶鏡開匣不是抽象好壞，而是一個有條件的過程：今日欣逢匣正開顯示限制，不管人間分萬類顯示轉折。對收入來源、交易成本、回收與風險而言，整體為吉。", "失物": "此項要從匣中寶鏡掛高臺與不管人間分萬類的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是被遮藏的能力或真相開始普照。因此評為吉。", "健康": "第37籤把局面寫成今日欣逢匣正開，最後以一時廣照在東來收束。套用到健康，應理解為被遮藏的能力或真相開始普照；在症狀變化、診療、休養與危險徵象上屬吉。", "總論": "問總論時，詩中匣中寶鏡掛高臺指出起因，一時廣照在東來交代結果。兩者合看，表示被遮藏的能力或真相開始普照。這項判為吉，須以實際條件是否符合詩中轉機為準。", "婚姻": "寶鏡開匣不是抽象好壞，而是一個有條件的過程：今日欣逢匣正開顯示限制，不管人間分萬類顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為吉。", "人際": "此項要從匣中寶鏡掛高臺與不管人間分萬類的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是被遮藏的能力或真相開始普照。因此評為吉。", "感情": "第37籤把局面寫成今日欣逢匣正開，最後以一時廣照在東來收束。套用到感情，應理解為被遮藏的能力或真相開始普照；在雙方意願、互動品質與情緒安全上屬吉。", "出行": "問出行時，詩中匣中寶鏡掛高臺指出起因，一時廣照在東來交代結果。兩者合看，表示被遮藏的能力或真相開始普照。這項判為吉，須以實際條件是否符合詩中轉機為準。", "家宅": "寶鏡開匣不是抽象好壞，而是一個有條件的過程：今日欣逢匣正開顯示限制，不管人間分萬類顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為吉。", "修心建議": "此項要從匣中寶鏡掛高臺與不管人間分萬類的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是被遮藏的能力或真相開始普照。因此評為吉。"}, "actionAdvice": ["先用匣中寶鏡掛高臺確認現況，再以今日欣逢匣正開找出限制，觀察不管人間分萬類所示轉折，最後依一時廣照在東來設定完成或停止條件。此籤的實際行動核心是：被遮藏的能力或真相開始普照。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 38, "displayNo": "第38籤", "level": "偏弱", "title": "保生大帝第38籤", "poem": ["牝雞鳴旦總非祥", "入室飛禽未為殃", "好念真經千萬遍", "家中方保再榮昌"], "story": "【家序失常】語見《尚書·牧誓》，古代用於批評秩序顛倒。現代資料只保存典源，不延伸為貶抑女性。", "classicMeaning": "", "plainMeaning": "第38籤主題為家序失常。四句由牝雞鳴旦總非祥起筆，經入室飛禽未為殃與好念真經千萬遍推進，以家中方保再榮昌收束。整體指出：秩序顛倒未必立刻成災，但需整頓家內規範。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中牝雞鳴旦總非祥指出起因，家中方保再榮昌交代結果。兩者合看，表示秩序顛倒未必立刻成災，但需整頓家內規範。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "考試": "家序失常不是抽象好壞，而是一個有條件的過程：入室飛禽未為殃顯示限制，好念真經千萬遍顯示轉折。對準備深度、評核時機與臨場表現而言，整體為偏弱。", "求財": "此項要從牝雞鳴旦總非祥與好念真經千萬遍的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是秩序顛倒未必立刻成災，但需整頓家內規範。因此評為偏弱。", "失物": "第38籤把局面寫成入室飛禽未為殃，最後以家中方保再榮昌收束。套用到失物，應理解為秩序顛倒未必立刻成災，但需整頓家內規範；在遺失路徑、可追查線索與尋回時效上屬偏弱。", "健康": "問健康時，詩中牝雞鳴旦總非祥指出起因，家中方保再榮昌交代結果。兩者合看，表示秩序顛倒未必立刻成災，但需整頓家內規範。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "總論": "家序失常不是抽象好壞，而是一個有條件的過程：入室飛禽未為殃顯示限制，好念真經千萬遍顯示轉折。對整體局勢、主要限制與轉機而言，整體為偏弱。", "婚姻": "此項要從牝雞鳴旦總非祥與好念真經千萬遍的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是秩序顛倒未必立刻成災，但需整頓家內規範。因此評為偏弱。", "人際": "第38籤把局面寫成入室飛禽未為殃，最後以家中方保再榮昌收束。套用到人際，應理解為秩序顛倒未必立刻成災，但需整頓家內規範；在信任、貴人、小人與溝通界線上屬偏弱。", "感情": "問感情時，詩中牝雞鳴旦總非祥指出起因，家中方保再榮昌交代結果。兩者合看，表示秩序顛倒未必立刻成災，但需整頓家內規範。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "出行": "家序失常不是抽象好壞，而是一個有條件的過程：入室飛禽未為殃顯示限制，好念真經千萬遍顯示轉折。對交通條件、方向、時機與人身安全而言，整體為偏弱。", "家宅": "此項要從牝雞鳴旦總非祥與好念真經千萬遍的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是秩序顛倒未必立刻成災，但需整頓家內規範。因此評為偏弱。", "修心建議": "第38籤把局面寫成入室飛禽未為殃，最後以家中方保再榮昌收束。套用到修心建議，應理解為秩序顛倒未必立刻成災，但需整頓家內規範；在品格、節制、反省與實際改過上屬偏弱。"}, "actionAdvice": ["先用牝雞鳴旦總非祥確認現況，再以入室飛禽未為殃找出限制，觀察好念真經千萬遍所示轉折，最後依家中方保再榮昌設定完成或停止條件。此籤的實際行動核心是：秩序顛倒未必立刻成災，但需整頓家內規範。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 39, "displayNo": "第39籤", "level": "偏弱", "title": "保生大帝第39籤", "poem": ["家門坎坷有些災", "口舌是非必破財", "若不破財災未免", "人丁損失見悲哀"], "story": "【破財消災】詩文直述破財與人丁之憂，應以風險防護而非宿命恐嚇解讀。", "classicMeaning": "", "plainMeaning": "第39籤主題為破財消災。四句由家門坎坷有些災起筆，經口舌是非必破財與若不破財災未免推進，以人丁損失見悲哀收束。整體指出：口舌與家門坎坷可能帶來財損，宜先止爭保人。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "破財消災不是抽象好壞，而是一個有條件的過程：口舌是非必破財顯示限制，若不破財災未免顯示轉折。對職位、合作、執行條件與責任界線而言，整體為偏弱。", "考試": "此項要從家門坎坷有些災與若不破財災未免的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是口舌與家門坎坷可能帶來財損，宜先止爭保人。因此評為偏弱。", "求財": "第39籤把局面寫成口舌是非必破財，最後以人丁損失見悲哀收束。套用到求財，應理解為口舌與家門坎坷可能帶來財損，宜先止爭保人；在收入來源、交易成本、回收與風險上屬偏弱。", "失物": "問失物時，詩中家門坎坷有些災指出起因，人丁損失見悲哀交代結果。兩者合看，表示口舌與家門坎坷可能帶來財損，宜先止爭保人。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "健康": "破財消災不是抽象好壞，而是一個有條件的過程：口舌是非必破財顯示限制，若不破財災未免顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為凶。", "總論": "此項要從家門坎坷有些災與若不破財災未免的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是口舌與家門坎坷可能帶來財損，宜先止爭保人。因此評為偏弱。", "婚姻": "第39籤把局面寫成口舌是非必破財，最後以人丁損失見悲哀收束。套用到婚姻，應理解為口舌與家門坎坷可能帶來財損，宜先止爭保人；在婚約、家庭共識、責任與長期相處上屬偏弱。", "人際": "問人際時，詩中家門坎坷有些災指出起因，人丁損失見悲哀交代結果。兩者合看，表示口舌與家門坎坷可能帶來財損，宜先止爭保人。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "感情": "破財消災不是抽象好壞，而是一個有條件的過程：口舌是非必破財顯示限制，若不破財災未免顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為偏弱。", "出行": "此項要從家門坎坷有些災與若不破財災未免的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是口舌與家門坎坷可能帶來財損，宜先止爭保人。因此評為偏弱。", "家宅": "第39籤把局面寫成口舌是非必破財，最後以人丁損失見悲哀收束。套用到家宅，應理解為口舌與家門坎坷可能帶來財損，宜先止爭保人；在家庭安寧、居所、修繕與財產安排上屬偏弱。", "修心建議": "問修心建議時，詩中家門坎坷有些災指出起因，人丁損失見悲哀交代結果。兩者合看，表示口舌與家門坎坷可能帶來財損，宜先止爭保人。這項判為偏弱，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用家門坎坷有些災確認現況，再以口舌是非必破財找出限制，觀察若不破財災未免所示轉折，最後依人丁損失見悲哀設定完成或停止條件。此籤的實際行動核心是：口舌與家門坎坷可能帶來財損，宜先止爭保人。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 40, "displayNo": "第40籤", "level": "偏弱", "title": "保生大帝第40籤", "poem": ["滿園雨雪落霏霏", "葉落山林樹影稀", "若問何時花正發", "也應守得到春暉"], "story": "【守候春暉】雨雪、葉落、春暉形成明確的物候等待。", "classicMeaning": "", "plainMeaning": "第40籤主題為守候春暉。四句由滿園雨雪落霏霏起筆，經葉落山林樹影稀與若問何時花正發推進，以也應守得到春暉收束。整體指出：寒冬葉落時不宜催花，耐心等季節轉換。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從滿園雨雪落霏霏與若問何時花正發的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是寒冬葉落時不宜催花，耐心等季節轉換。因此評為偏弱。", "考試": "第40籤把局面寫成葉落山林樹影稀，最後以也應守得到春暉收束。套用到考試，應理解為寒冬葉落時不宜催花，耐心等季節轉換；在準備深度、評核時機與臨場表現上屬偏弱。", "求財": "問求財時，詩中滿園雨雪落霏霏指出起因，也應守得到春暉交代結果。兩者合看，表示寒冬葉落時不宜催花，耐心等季節轉換。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "失物": "守候春暉不是抽象好壞，而是一個有條件的過程：葉落山林樹影稀顯示限制，若問何時花正發顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為偏弱。", "健康": "此項要從滿園雨雪落霏霏與若問何時花正發的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是寒冬葉落時不宜催花，耐心等季節轉換。因此評為偏弱。", "總論": "第40籤把局面寫成葉落山林樹影稀，最後以也應守得到春暉收束。套用到總論，應理解為寒冬葉落時不宜催花，耐心等季節轉換；在整體局勢、主要限制與轉機上屬偏弱。", "婚姻": "問婚姻時，詩中滿園雨雪落霏霏指出起因，也應守得到春暉交代結果。兩者合看，表示寒冬葉落時不宜催花，耐心等季節轉換。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "人際": "守候春暉不是抽象好壞，而是一個有條件的過程：葉落山林樹影稀顯示限制，若問何時花正發顯示轉折。對信任、貴人、小人與溝通界線而言，整體為偏弱。", "感情": "此項要從滿園雨雪落霏霏與若問何時花正發的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是寒冬葉落時不宜催花，耐心等季節轉換。因此評為偏弱。", "出行": "第40籤把局面寫成葉落山林樹影稀，最後以也應守得到春暉收束。套用到出行，應理解為寒冬葉落時不宜催花，耐心等季節轉換；在交通條件、方向、時機與人身安全上屬偏弱。", "家宅": "問家宅時，詩中滿園雨雪落霏霏指出起因，也應守得到春暉交代結果。兩者合看，表示寒冬葉落時不宜催花，耐心等季節轉換。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "修心建議": "守候春暉不是抽象好壞，而是一個有條件的過程：葉落山林樹影稀顯示限制，若問何時花正發顯示轉折。對品格、節制、反省與實際改過而言，整體為偏弱。"}, "actionAdvice": ["先用滿園雨雪落霏霏確認現況，再以葉落山林樹影稀找出限制，觀察若問何時花正發所示轉折，最後依也應守得到春暉設定完成或停止條件。此籤的實際行動核心是：寒冬葉落時不宜催花，耐心等季節轉換。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 41, "displayNo": "第41籤", "level": "偏弱", "title": "保生大帝第41籤", "poem": ["欲來時早起風雲", "官職宣遷意不勤", "正好行程偏宿住", "爐香今日盡燒焚"], "story": "【機會受滯】官職宣遷與偏宿住形成機會來而人未動的張力。", "classicMeaning": "", "plainMeaning": "第41籤主題為機會受滯。四句由欲來時早起風雲起筆，經官職宣遷意不勤與正好行程偏宿住推進，以爐香今日盡燒焚收束。整體指出：風雲已起卻因意志或住宿延誤，升遷行程未能及時承接。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第41籤把局面寫成官職宣遷意不勤，最後以爐香今日盡燒焚收束。套用到事業，應理解為風雲已起卻因意志或住宿延誤，升遷行程未能及時承接；在職位、合作、執行條件與責任界線上屬平。", "考試": "問考試時，詩中欲來時早起風雲指出起因，爐香今日盡燒焚交代結果。兩者合看，表示風雲已起卻因意志或住宿延誤，升遷行程未能及時承接。這項判為平，須以實際條件是否符合詩中轉機為準。", "求財": "機會受滯不是抽象好壞，而是一個有條件的過程：官職宣遷意不勤顯示限制，正好行程偏宿住顯示轉折。對收入來源、交易成本、回收與風險而言，整體為平。", "失物": "此項要從欲來時早起風雲與正好行程偏宿住的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是風雲已起卻因意志或住宿延誤，升遷行程未能及時承接。因此評為偏弱。", "健康": "第41籤把局面寫成官職宣遷意不勤，最後以爐香今日盡燒焚收束。套用到健康，應理解為風雲已起卻因意志或住宿延誤，升遷行程未能及時承接；在症狀變化、診療、休養與危險徵象上屬偏弱。", "總論": "問總論時，詩中欲來時早起風雲指出起因，爐香今日盡燒焚交代結果。兩者合看，表示風雲已起卻因意志或住宿延誤，升遷行程未能及時承接。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "婚姻": "機會受滯不是抽象好壞，而是一個有條件的過程：官職宣遷意不勤顯示限制，正好行程偏宿住顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為偏弱。", "人際": "此項要從欲來時早起風雲與正好行程偏宿住的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是風雲已起卻因意志或住宿延誤，升遷行程未能及時承接。因此評為偏弱。", "感情": "第41籤把局面寫成官職宣遷意不勤，最後以爐香今日盡燒焚收束。套用到感情，應理解為風雲已起卻因意志或住宿延誤，升遷行程未能及時承接；在雙方意願、互動品質與情緒安全上屬偏弱。", "出行": "問出行時，詩中欲來時早起風雲指出起因，爐香今日盡燒焚交代結果。兩者合看，表示風雲已起卻因意志或住宿延誤，升遷行程未能及時承接。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "家宅": "機會受滯不是抽象好壞，而是一個有條件的過程：官職宣遷意不勤顯示限制，正好行程偏宿住顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為偏弱。", "修心建議": "此項要從欲來時早起風雲與正好行程偏宿住的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是風雲已起卻因意志或住宿延誤，升遷行程未能及時承接。因此評為偏弱。"}, "actionAdvice": ["先用欲來時早起風雲確認現況，再以官職宣遷意不勤找出限制，觀察正好行程偏宿住所示轉折，最後依爐香今日盡燒焚設定完成或停止條件。此籤的實際行動核心是：風雲已起卻因意志或住宿延誤，升遷行程未能及時承接。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 42, "displayNo": "第42籤", "level": "平", "title": "保生大帝第42籤", "poem": ["性質原來騎駿馬", "今朝卻換此駑駘", "欲知善惡須知相", "伯樂分明為主裁"], "story": "【伯樂識馬】伯樂被傳為善相馬者，後世以伯樂比喻能識別人才的人。", "classicMeaning": "", "plainMeaning": "第42籤主題為伯樂識馬。四句由性質原來騎駿馬起筆，經今朝卻換此駑駘與欲知善惡須知相推進，以伯樂分明為主裁收束。整體指出：能力與位置不相稱，需要真正懂行者判別。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中性質原來騎駿馬指出起因，伯樂分明為主裁交代結果。兩者合看，表示能力與位置不相稱，需要真正懂行者判別。這項判為吉，須以實際條件是否符合詩中轉機為準。", "考試": "伯樂識馬不是抽象好壞，而是一個有條件的過程：今朝卻換此駑駘顯示限制，欲知善惡須知相顯示轉折。對準備深度、評核時機與臨場表現而言，整體為吉。", "求財": "此項要從性質原來騎駿馬與欲知善惡須知相的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是能力與位置不相稱，需要真正懂行者判別。因此評為吉。", "失物": "第42籤把局面寫成今朝卻換此駑駘，最後以伯樂分明為主裁收束。套用到失物，應理解為能力與位置不相稱，需要真正懂行者判別；在遺失路徑、可追查線索與尋回時效上屬平。", "健康": "問健康時，詩中性質原來騎駿馬指出起因，伯樂分明為主裁交代結果。兩者合看，表示能力與位置不相稱，需要真正懂行者判別。這項判為平，須以實際條件是否符合詩中轉機為準。", "總論": "伯樂識馬不是抽象好壞，而是一個有條件的過程：今朝卻換此駑駘顯示限制，欲知善惡須知相顯示轉折。對整體局勢、主要限制與轉機而言，整體為平。", "婚姻": "此項要從性質原來騎駿馬與欲知善惡須知相的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是能力與位置不相稱，需要真正懂行者判別。因此評為平。", "人際": "第42籤把局面寫成今朝卻換此駑駘，最後以伯樂分明為主裁收束。套用到人際，應理解為能力與位置不相稱，需要真正懂行者判別；在信任、貴人、小人與溝通界線上屬平。", "感情": "問感情時，詩中性質原來騎駿馬指出起因，伯樂分明為主裁交代結果。兩者合看，表示能力與位置不相稱，需要真正懂行者判別。這項判為平，須以實際條件是否符合詩中轉機為準。", "出行": "伯樂識馬不是抽象好壞，而是一個有條件的過程：今朝卻換此駑駘顯示限制，欲知善惡須知相顯示轉折。對交通條件、方向、時機與人身安全而言，整體為平。", "家宅": "此項要從性質原來騎駿馬與欲知善惡須知相的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是能力與位置不相稱，需要真正懂行者判別。因此評為平。", "修心建議": "第42籤把局面寫成今朝卻換此駑駘，最後以伯樂分明為主裁收束。套用到修心建議，應理解為能力與位置不相稱，需要真正懂行者判別；在品格、節制、反省與實際改過上屬平。"}, "actionAdvice": ["先用性質原來騎駿馬確認現況，再以今朝卻換此駑駘找出限制，觀察欲知善惡須知相所示轉折，最後依伯樂分明為主裁設定完成或停止條件。此籤的實際行動核心是：能力與位置不相稱，需要真正懂行者判別。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 43, "displayNo": "第43籤", "level": "吉", "title": "保生大帝第43籤", "poem": ["畫燭當空焰焰燒", "琉璃瓶在水中漂", "勿驚風浪隨流轉", "可保安然不動搖"], "story": "【隨流不覆】琉璃瓶漂水易碎，能不動搖全賴穩定與順勢。", "classicMeaning": "", "plainMeaning": "第43籤主題為隨流不覆。四句由畫燭當空焰焰燒起筆，經琉璃瓶在水中漂與勿驚風浪隨流轉推進，以可保安然不動搖收束。整體指出：外界有風浪但核心尚可保持。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "隨流不覆不是抽象好壞，而是一個有條件的過程：琉璃瓶在水中漂顯示限制，勿驚風浪隨流轉顯示轉折。對職位、合作、執行條件與責任界線而言，整體為吉。", "考試": "此項要從畫燭當空焰焰燒與勿驚風浪隨流轉的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是外界有風浪但核心尚可保持。因此評為吉。", "求財": "第43籤把局面寫成琉璃瓶在水中漂，最後以可保安然不動搖收束。套用到求財，應理解為外界有風浪但核心尚可保持；在收入來源、交易成本、回收與風險上屬吉。", "失物": "問失物時，詩中畫燭當空焰焰燒指出起因，可保安然不動搖交代結果。兩者合看，表示外界有風浪但核心尚可保持。這項判為吉，須以實際條件是否符合詩中轉機為準。", "健康": "隨流不覆不是抽象好壞，而是一個有條件的過程：琉璃瓶在水中漂顯示限制，勿驚風浪隨流轉顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為吉。", "總論": "此項要從畫燭當空焰焰燒與勿驚風浪隨流轉的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是外界有風浪但核心尚可保持。因此評為吉。", "婚姻": "第43籤把局面寫成琉璃瓶在水中漂，最後以可保安然不動搖收束。套用到婚姻，應理解為外界有風浪但核心尚可保持；在婚約、家庭共識、責任與長期相處上屬吉。", "人際": "問人際時，詩中畫燭當空焰焰燒指出起因，可保安然不動搖交代結果。兩者合看，表示外界有風浪但核心尚可保持。這項判為吉，須以實際條件是否符合詩中轉機為準。", "感情": "隨流不覆不是抽象好壞，而是一個有條件的過程：琉璃瓶在水中漂顯示限制，勿驚風浪隨流轉顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為吉。", "出行": "此項要從畫燭當空焰焰燒與勿驚風浪隨流轉的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是外界有風浪但核心尚可保持。因此評為吉。", "家宅": "第43籤把局面寫成琉璃瓶在水中漂，最後以可保安然不動搖收束。套用到家宅，應理解為外界有風浪但核心尚可保持；在家庭安寧、居所、修繕與財產安排上屬吉。", "修心建議": "問修心建議時，詩中畫燭當空焰焰燒指出起因，可保安然不動搖交代結果。兩者合看，表示外界有風浪但核心尚可保持。這項判為吉，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用畫燭當空焰焰燒確認現況，再以琉璃瓶在水中漂找出限制，觀察勿驚風浪隨流轉所示轉折，最後依可保安然不動搖設定完成或停止條件。此籤的實際行動核心是：外界有風浪但核心尚可保持。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 44, "displayNo": "第44籤", "level": "偏弱", "title": "保生大帝第44籤", "poem": ["夜行燈火中途滅", "寂寂人間暗自傷", "敲門入室喚他醒", "起來無火也難當"], "story": "【中途失火】夜行失燈是方向、資訊與能量中斷的直觀警示。", "classicMeaning": "", "plainMeaning": "第44籤主題為中途失火。四句由夜行燈火中途滅起筆，經寂寂人間暗自傷與敲門入室喚他醒推進，以起來無火也難當收束。整體指出：關鍵資源在半途消失，臨時求援也未必立即補上。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從夜行燈火中途滅與敲門入室喚他醒的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是關鍵資源在半途消失，臨時求援也未必立即補上。因此評為偏弱。", "考試": "第44籤把局面寫成寂寂人間暗自傷，最後以起來無火也難當收束。套用到考試，應理解為關鍵資源在半途消失，臨時求援也未必立即補上；在準備深度、評核時機與臨場表現上屬偏弱。", "求財": "問求財時，詩中夜行燈火中途滅指出起因，起來無火也難當交代結果。兩者合看，表示關鍵資源在半途消失，臨時求援也未必立即補上。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "失物": "中途失火不是抽象好壞，而是一個有條件的過程：寂寂人間暗自傷顯示限制，敲門入室喚他醒顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為偏弱。", "健康": "此項要從夜行燈火中途滅與敲門入室喚他醒的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是關鍵資源在半途消失，臨時求援也未必立即補上。因此評為凶。", "總論": "第44籤把局面寫成寂寂人間暗自傷，最後以起來無火也難當收束。套用到總論，應理解為關鍵資源在半途消失，臨時求援也未必立即補上；在整體局勢、主要限制與轉機上屬偏弱。", "婚姻": "問婚姻時，詩中夜行燈火中途滅指出起因，起來無火也難當交代結果。兩者合看，表示關鍵資源在半途消失，臨時求援也未必立即補上。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "人際": "中途失火不是抽象好壞，而是一個有條件的過程：寂寂人間暗自傷顯示限制，敲門入室喚他醒顯示轉折。對信任、貴人、小人與溝通界線而言，整體為偏弱。", "感情": "此項要從夜行燈火中途滅與敲門入室喚他醒的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是關鍵資源在半途消失，臨時求援也未必立即補上。因此評為偏弱。", "出行": "第44籤把局面寫成寂寂人間暗自傷，最後以起來無火也難當收束。套用到出行，應理解為關鍵資源在半途消失，臨時求援也未必立即補上；在交通條件、方向、時機與人身安全上屬凶。", "家宅": "問家宅時，詩中夜行燈火中途滅指出起因，起來無火也難當交代結果。兩者合看，表示關鍵資源在半途消失，臨時求援也未必立即補上。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "修心建議": "中途失火不是抽象好壞，而是一個有條件的過程：寂寂人間暗自傷顯示限制，敲門入室喚他醒顯示轉折。對品格、節制、反省與實際改過而言，整體為偏弱。"}, "actionAdvice": ["先用夜行燈火中途滅確認現況，再以寂寂人間暗自傷找出限制，觀察敲門入室喚他醒所示轉折，最後依起來無火也難當設定完成或停止條件。此籤的實際行動核心是：關鍵資源在半途消失，臨時求援也未必立即補上。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 45, "displayNo": "第45籤", "level": "偏弱", "title": "保生大帝第45籤", "poem": ["忍耐溪邊人養鴨", "縱無煩惱也勞心", "滔滔遊入江中去", "岸上呼聲那得尋"], "story": "【放手難追】養鴨入江比喻投入失控與成果流失。", "classicMeaning": "", "plainMeaning": "第45籤主題為放手難追。四句由忍耐溪邊人養鴨起筆，經縱無煩惱也勞心與滔滔遊入江中去推進，以岸上呼聲那得尋收束。整體指出：長期照料之物一旦入大江，岸上呼喊已難追回。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第45籤把局面寫成縱無煩惱也勞心，最後以岸上呼聲那得尋收束。套用到事業，應理解為長期照料之物一旦入大江，岸上呼喊已難追回；在職位、合作、執行條件與責任界線上屬偏弱。", "考試": "問考試時，詩中忍耐溪邊人養鴨指出起因，岸上呼聲那得尋交代結果。兩者合看，表示長期照料之物一旦入大江，岸上呼喊已難追回。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "求財": "放手難追不是抽象好壞，而是一個有條件的過程：縱無煩惱也勞心顯示限制，滔滔遊入江中去顯示轉折。對收入來源、交易成本、回收與風險而言，整體為偏弱。", "失物": "此項要從忍耐溪邊人養鴨與滔滔遊入江中去的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是長期照料之物一旦入大江，岸上呼喊已難追回。因此評為偏弱。", "健康": "第45籤把局面寫成縱無煩惱也勞心，最後以岸上呼聲那得尋收束。套用到健康，應理解為長期照料之物一旦入大江，岸上呼喊已難追回；在症狀變化、診療、休養與危險徵象上屬偏弱。", "總論": "問總論時，詩中忍耐溪邊人養鴨指出起因，岸上呼聲那得尋交代結果。兩者合看，表示長期照料之物一旦入大江，岸上呼喊已難追回。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "婚姻": "放手難追不是抽象好壞，而是一個有條件的過程：縱無煩惱也勞心顯示限制，滔滔遊入江中去顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為偏弱。", "人際": "此項要從忍耐溪邊人養鴨與滔滔遊入江中去的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是長期照料之物一旦入大江，岸上呼喊已難追回。因此評為偏弱。", "感情": "第45籤把局面寫成縱無煩惱也勞心，最後以岸上呼聲那得尋收束。套用到感情，應理解為長期照料之物一旦入大江，岸上呼喊已難追回；在雙方意願、互動品質與情緒安全上屬偏弱。", "出行": "問出行時，詩中忍耐溪邊人養鴨指出起因，岸上呼聲那得尋交代結果。兩者合看，表示長期照料之物一旦入大江，岸上呼喊已難追回。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "家宅": "放手難追不是抽象好壞，而是一個有條件的過程：縱無煩惱也勞心顯示限制，滔滔遊入江中去顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為偏弱。", "修心建議": "此項要從忍耐溪邊人養鴨與滔滔遊入江中去的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是長期照料之物一旦入大江，岸上呼喊已難追回。因此評為偏弱。"}, "actionAdvice": ["先用忍耐溪邊人養鴨確認現況，再以縱無煩惱也勞心找出限制，觀察滔滔遊入江中去所示轉折，最後依岸上呼聲那得尋設定完成或停止條件。此籤的實際行動核心是：長期照料之物一旦入大江，岸上呼喊已難追回。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 46, "displayNo": "第46籤", "level": "吉", "title": "保生大帝第46籤", "poem": ["浴出龍池妙色身", "老君抱送玉麒麟", "鮮花玉蕊呈祥瑞", "頂上摩尼珠一新"], "story": "【麒麟呈瑞】麒麟在民間有送子、嘉瑞意涵；摩尼珠源自佛教寶珠譬喻。兩者在籤中共同指向珍貴新生。", "classicMeaning": "", "plainMeaning": "第46籤主題為麒麟呈瑞。四句由浴出龍池妙色身起筆，經老君抱送玉麒麟與鮮花玉蕊呈祥瑞推進，以頂上摩尼珠一新收束。整體指出：新生、才華或珍貴成果顯現。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中浴出龍池妙色身指出起因，頂上摩尼珠一新交代結果。兩者合看，表示新生、才華或珍貴成果顯現。這項判為吉，須以實際條件是否符合詩中轉機為準。", "考試": "麒麟呈瑞不是抽象好壞，而是一個有條件的過程：老君抱送玉麒麟顯示限制，鮮花玉蕊呈祥瑞顯示轉折。對準備深度、評核時機與臨場表現而言，整體為吉。", "求財": "此項要從浴出龍池妙色身與鮮花玉蕊呈祥瑞的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是新生、才華或珍貴成果顯現。因此評為吉。", "失物": "第46籤把局面寫成老君抱送玉麒麟，最後以頂上摩尼珠一新收束。套用到失物，應理解為新生、才華或珍貴成果顯現；在遺失路徑、可追查線索與尋回時效上屬吉。", "健康": "問健康時，詩中浴出龍池妙色身指出起因，頂上摩尼珠一新交代結果。兩者合看，表示新生、才華或珍貴成果顯現。這項判為吉，須以實際條件是否符合詩中轉機為準。", "總論": "麒麟呈瑞不是抽象好壞，而是一個有條件的過程：老君抱送玉麒麟顯示限制，鮮花玉蕊呈祥瑞顯示轉折。對整體局勢、主要限制與轉機而言，整體為吉。", "婚姻": "此項要從浴出龍池妙色身與鮮花玉蕊呈祥瑞的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是新生、才華或珍貴成果顯現。因此評為吉。", "人際": "第46籤把局面寫成老君抱送玉麒麟，最後以頂上摩尼珠一新收束。套用到人際，應理解為新生、才華或珍貴成果顯現；在信任、貴人、小人與溝通界線上屬吉。", "感情": "問感情時，詩中浴出龍池妙色身指出起因，頂上摩尼珠一新交代結果。兩者合看，表示新生、才華或珍貴成果顯現。這項判為吉，須以實際條件是否符合詩中轉機為準。", "出行": "麒麟呈瑞不是抽象好壞，而是一個有條件的過程：老君抱送玉麒麟顯示限制，鮮花玉蕊呈祥瑞顯示轉折。對交通條件、方向、時機與人身安全而言，整體為吉。", "家宅": "此項要從浴出龍池妙色身與鮮花玉蕊呈祥瑞的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是新生、才華或珍貴成果顯現。因此評為吉。", "修心建議": "第46籤把局面寫成老君抱送玉麒麟，最後以頂上摩尼珠一新收束。套用到修心建議，應理解為新生、才華或珍貴成果顯現；在品格、節制、反省與實際改過上屬吉。"}, "actionAdvice": ["先用浴出龍池妙色身確認現況，再以老君抱送玉麒麟找出限制，觀察鮮花玉蕊呈祥瑞所示轉折，最後依頂上摩尼珠一新設定完成或停止條件。此籤的實際行動核心是：新生、才華或珍貴成果顯現。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 47, "displayNo": "第47籤", "level": "偏弱", "title": "保生大帝第47籤", "poem": ["畫匣新妝滿鏡花", "凝眸端正足堪誇", "欲折一枝歸去賞", "那堪再取惹交加"], "story": "【一枝足賞】鏡花與折枝皆美，但再取便成過度占有。", "classicMeaning": "", "plainMeaning": "第47籤主題為一枝足賞。四句由畫匣新妝滿鏡花起筆，經凝眸端正足堪誇與欲折一枝歸去賞推進，以那堪再取惹交加收束。整體指出：已有美好成果，不可因貪多而惹糾葛。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "一枝足賞不是抽象好壞，而是一個有條件的過程：凝眸端正足堪誇顯示限制，欲折一枝歸去賞顯示轉折。對職位、合作、執行條件與責任界線而言，整體為偏弱。", "考試": "此項要從畫匣新妝滿鏡花與欲折一枝歸去賞的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是已有美好成果，不可因貪多而惹糾葛。因此評為偏弱。", "求財": "第47籤把局面寫成凝眸端正足堪誇，最後以那堪再取惹交加收束。套用到求財，應理解為已有美好成果，不可因貪多而惹糾葛；在收入來源、交易成本、回收與風險上屬偏弱。", "失物": "問失物時，詩中畫匣新妝滿鏡花指出起因，那堪再取惹交加交代結果。兩者合看，表示已有美好成果，不可因貪多而惹糾葛。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "健康": "一枝足賞不是抽象好壞，而是一個有條件的過程：凝眸端正足堪誇顯示限制，欲折一枝歸去賞顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為偏弱。", "總論": "此項要從畫匣新妝滿鏡花與欲折一枝歸去賞的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是已有美好成果，不可因貪多而惹糾葛。因此評為偏弱。", "婚姻": "第47籤把局面寫成凝眸端正足堪誇，最後以那堪再取惹交加收束。套用到婚姻，應理解為已有美好成果，不可因貪多而惹糾葛；在婚約、家庭共識、責任與長期相處上屬偏弱。", "人際": "問人際時，詩中畫匣新妝滿鏡花指出起因，那堪再取惹交加交代結果。兩者合看，表示已有美好成果，不可因貪多而惹糾葛。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "感情": "一枝足賞不是抽象好壞，而是一個有條件的過程：凝眸端正足堪誇顯示限制，欲折一枝歸去賞顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為偏弱。", "出行": "此項要從畫匣新妝滿鏡花與欲折一枝歸去賞的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是已有美好成果，不可因貪多而惹糾葛。因此評為偏弱。", "家宅": "第47籤把局面寫成凝眸端正足堪誇，最後以那堪再取惹交加收束。套用到家宅，應理解為已有美好成果，不可因貪多而惹糾葛；在家庭安寧、居所、修繕與財產安排上屬偏弱。", "修心建議": "問修心建議時，詩中畫匣新妝滿鏡花指出起因，那堪再取惹交加交代結果。兩者合看，表示已有美好成果，不可因貪多而惹糾葛。這項判為偏弱，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用畫匣新妝滿鏡花確認現況，再以凝眸端正足堪誇找出限制，觀察欲折一枝歸去賞所示轉折，最後依那堪再取惹交加設定完成或停止條件。此籤的實際行動核心是：已有美好成果，不可因貪多而惹糾葛。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 48, "displayNo": "第48籤", "level": "偏弱", "title": "保生大帝第48籤", "poem": ["煌煌秉燭正元宵", "鬥火飛蛾自損燒", "高掛銀臺端正坐", "陽光照耀必無饒"], "story": "【飛蛾自焚】飛蛾撲火是受誘惑而自損的典型譬喻。", "classicMeaning": "", "plainMeaning": "第48籤主題為飛蛾自焚。四句由煌煌秉燭正元宵起筆，經鬥火飛蛾自損燒與高掛銀臺端正坐推進，以陽光照耀必無饒收束。整體指出：明火可照人，也會燒傷盲目撲火者。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從煌煌秉燭正元宵與高掛銀臺端正坐的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是明火可照人，也會燒傷盲目撲火者。因此評為偏弱。", "考試": "第48籤把局面寫成鬥火飛蛾自損燒，最後以陽光照耀必無饒收束。套用到考試，應理解為明火可照人，也會燒傷盲目撲火者；在準備深度、評核時機與臨場表現上屬偏弱。", "求財": "問求財時，詩中煌煌秉燭正元宵指出起因，陽光照耀必無饒交代結果。兩者合看，表示明火可照人，也會燒傷盲目撲火者。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "失物": "飛蛾自焚不是抽象好壞，而是一個有條件的過程：鬥火飛蛾自損燒顯示限制，高掛銀臺端正坐顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為偏弱。", "健康": "此項要從煌煌秉燭正元宵與高掛銀臺端正坐的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是明火可照人，也會燒傷盲目撲火者。因此評為凶。", "總論": "第48籤把局面寫成鬥火飛蛾自損燒，最後以陽光照耀必無饒收束。套用到總論，應理解為明火可照人，也會燒傷盲目撲火者；在整體局勢、主要限制與轉機上屬偏弱。", "婚姻": "問婚姻時，詩中煌煌秉燭正元宵指出起因，陽光照耀必無饒交代結果。兩者合看，表示明火可照人，也會燒傷盲目撲火者。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "人際": "飛蛾自焚不是抽象好壞，而是一個有條件的過程：鬥火飛蛾自損燒顯示限制，高掛銀臺端正坐顯示轉折。對信任、貴人、小人與溝通界線而言，整體為偏弱。", "感情": "此項要從煌煌秉燭正元宵與高掛銀臺端正坐的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是明火可照人，也會燒傷盲目撲火者。因此評為偏弱。", "出行": "第48籤把局面寫成鬥火飛蛾自損燒，最後以陽光照耀必無饒收束。套用到出行，應理解為明火可照人，也會燒傷盲目撲火者；在交通條件、方向、時機與人身安全上屬偏弱。", "家宅": "問家宅時，詩中煌煌秉燭正元宵指出起因，陽光照耀必無饒交代結果。兩者合看，表示明火可照人，也會燒傷盲目撲火者。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "修心建議": "飛蛾自焚不是抽象好壞，而是一個有條件的過程：鬥火飛蛾自損燒顯示限制，高掛銀臺端正坐顯示轉折。對品格、節制、反省與實際改過而言，整體為偏弱。"}, "actionAdvice": ["先用煌煌秉燭正元宵確認現況，再以鬥火飛蛾自損燒找出限制，觀察高掛銀臺端正坐所示轉折，最後依陽光照耀必無饒設定完成或停止條件。此籤的實際行動核心是：明火可照人，也會燒傷盲目撲火者。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 49, "displayNo": "第49籤", "level": "吉", "title": "保生大帝第49籤", "poem": ["清江鼓棹月盈船", "水壓中天盡可觀", "幸禱至誠天眷佑", "何愁首尾不安全"], "story": "【首尾安全】鼓棹清江是主動行舟；首尾安全表示開始與收束都須顧全。", "classicMeaning": "", "plainMeaning": "第49籤主題為首尾安全。四句由清江鼓棹月盈船起筆，經水壓中天盡可觀與幸禱至誠天眷佑推進，以何愁首尾不安全收束。整體指出：舟行有月、至誠得佑，重點在全程維持安全。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第49籤把局面寫成水壓中天盡可觀，最後以何愁首尾不安全收束。套用到事業，應理解為舟行有月、至誠得佑，重點在全程維持安全；在職位、合作、執行條件與責任界線上屬吉。", "考試": "問考試時，詩中清江鼓棹月盈船指出起因，何愁首尾不安全交代結果。兩者合看，表示舟行有月、至誠得佑，重點在全程維持安全。這項判為吉，須以實際條件是否符合詩中轉機為準。", "求財": "首尾安全不是抽象好壞，而是一個有條件的過程：水壓中天盡可觀顯示限制，幸禱至誠天眷佑顯示轉折。對收入來源、交易成本、回收與風險而言，整體為吉。", "失物": "此項要從清江鼓棹月盈船與幸禱至誠天眷佑的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是舟行有月、至誠得佑，重點在全程維持安全。因此評為吉。", "健康": "第49籤把局面寫成水壓中天盡可觀，最後以何愁首尾不安全收束。套用到健康，應理解為舟行有月、至誠得佑，重點在全程維持安全；在症狀變化、診療、休養與危險徵象上屬大吉。", "總論": "問總論時，詩中清江鼓棹月盈船指出起因，何愁首尾不安全交代結果。兩者合看，表示舟行有月、至誠得佑，重點在全程維持安全。這項判為吉，須以實際條件是否符合詩中轉機為準。", "婚姻": "首尾安全不是抽象好壞，而是一個有條件的過程：水壓中天盡可觀顯示限制，幸禱至誠天眷佑顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為吉。", "人際": "此項要從清江鼓棹月盈船與幸禱至誠天眷佑的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是舟行有月、至誠得佑，重點在全程維持安全。因此評為吉。", "感情": "第49籤把局面寫成水壓中天盡可觀，最後以何愁首尾不安全收束。套用到感情，應理解為舟行有月、至誠得佑，重點在全程維持安全；在雙方意願、互動品質與情緒安全上屬吉。", "出行": "問出行時，詩中清江鼓棹月盈船指出起因，何愁首尾不安全交代結果。兩者合看，表示舟行有月、至誠得佑，重點在全程維持安全。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "家宅": "首尾安全不是抽象好壞，而是一個有條件的過程：水壓中天盡可觀顯示限制，幸禱至誠天眷佑顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為吉。", "修心建議": "此項要從清江鼓棹月盈船與幸禱至誠天眷佑的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是舟行有月、至誠得佑，重點在全程維持安全。因此評為吉。"}, "actionAdvice": ["先用清江鼓棹月盈船確認現況，再以水壓中天盡可觀找出限制，觀察幸禱至誠天眷佑所示轉折，最後依何愁首尾不安全設定完成或停止條件。此籤的實際行動核心是：舟行有月、至誠得佑，重點在全程維持安全。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 50, "displayNo": "第50籤", "level": "吉", "title": "保生大帝第50籤", "poem": ["日月何曾照覆盆", "而今且在暗中存", "貴人不久提攜去", "早晚知君得處尊"], "story": "【覆盆待照】覆盆之下不見日月，常用來比喻幽暗、冤屈或長期不被看見。", "classicMeaning": "", "plainMeaning": "第50籤主題為覆盆待照。四句由日月何曾照覆盆起筆，經而今且在暗中存與貴人不久提攜去推進，以早晚知君得處尊收束。整體指出：長期被遮蔽者將得貴人提攜。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中日月何曾照覆盆指出起因，早晚知君得處尊交代結果。兩者合看，表示長期被遮蔽者將得貴人提攜。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "考試": "覆盆待照不是抽象好壞，而是一個有條件的過程：而今且在暗中存顯示限制，貴人不久提攜去顯示轉折。對準備深度、評核時機與臨場表現而言，整體為大吉。", "求財": "此項要從日月何曾照覆盆與貴人不久提攜去的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是長期被遮蔽者將得貴人提攜。因此評為大吉。", "失物": "第50籤把局面寫成而今且在暗中存，最後以早晚知君得處尊收束。套用到失物，應理解為長期被遮蔽者將得貴人提攜；在遺失路徑、可追查線索與尋回時效上屬吉。", "健康": "問健康時，詩中日月何曾照覆盆指出起因，早晚知君得處尊交代結果。兩者合看，表示長期被遮蔽者將得貴人提攜。這項判為吉，須以實際條件是否符合詩中轉機為準。", "總論": "覆盆待照不是抽象好壞，而是一個有條件的過程：而今且在暗中存顯示限制，貴人不久提攜去顯示轉折。對整體局勢、主要限制與轉機而言，整體為吉。", "婚姻": "此項要從日月何曾照覆盆與貴人不久提攜去的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是長期被遮蔽者將得貴人提攜。因此評為吉。", "人際": "第50籤把局面寫成而今且在暗中存，最後以早晚知君得處尊收束。套用到人際，應理解為長期被遮蔽者將得貴人提攜；在信任、貴人、小人與溝通界線上屬吉。", "感情": "問感情時，詩中日月何曾照覆盆指出起因，早晚知君得處尊交代結果。兩者合看，表示長期被遮蔽者將得貴人提攜。這項判為吉，須以實際條件是否符合詩中轉機為準。", "出行": "覆盆待照不是抽象好壞，而是一個有條件的過程：而今且在暗中存顯示限制，貴人不久提攜去顯示轉折。對交通條件、方向、時機與人身安全而言，整體為吉。", "家宅": "此項要從日月何曾照覆盆與貴人不久提攜去的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是長期被遮蔽者將得貴人提攜。因此評為吉。", "修心建議": "第50籤把局面寫成而今且在暗中存，最後以早晚知君得處尊收束。套用到修心建議，應理解為長期被遮蔽者將得貴人提攜；在品格、節制、反省與實際改過上屬吉。"}, "actionAdvice": ["先用日月何曾照覆盆確認現況，再以而今且在暗中存找出限制，觀察貴人不久提攜去所示轉折，最後依早晚知君得處尊設定完成或停止條件。此籤的實際行動核心是：長期被遮蔽者將得貴人提攜。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 51, "displayNo": "第51籤", "level": "偏弱", "title": "保生大帝第51籤", "poem": ["夜夢堪嗟大不祥", "醉中未有亂顛狂", "但存心正相安處", "早晚虔燒一柱香"], "story": "【夢凶心正】詩中明確把夢境與實際操守分開，不宜迷信夢兆。", "classicMeaning": "", "plainMeaning": "第51籤主題為夢凶心正。四句由夜夢堪嗟大不祥起筆，經醉中未有亂顛狂與但存心正相安處推進，以早晚虔燒一柱香收束。整體指出：外在夢兆令人不安，但清醒時守正可安。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "夢凶心正不是抽象好壞，而是一個有條件的過程：醉中未有亂顛狂顯示限制，但存心正相安處顯示轉折。對職位、合作、執行條件與責任界線而言，整體為偏弱。", "考試": "此項要從夜夢堪嗟大不祥與但存心正相安處的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是外在夢兆令人不安，但清醒時守正可安。因此評為偏弱。", "求財": "第51籤把局面寫成醉中未有亂顛狂，最後以早晚虔燒一柱香收束。套用到求財，應理解為外在夢兆令人不安，但清醒時守正可安；在收入來源、交易成本、回收與風險上屬偏弱。", "失物": "問失物時，詩中夜夢堪嗟大不祥指出起因，早晚虔燒一柱香交代結果。兩者合看，表示外在夢兆令人不安，但清醒時守正可安。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "健康": "夢凶心正不是抽象好壞，而是一個有條件的過程：醉中未有亂顛狂顯示限制，但存心正相安處顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為偏弱。", "總論": "此項要從夜夢堪嗟大不祥與但存心正相安處的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是外在夢兆令人不安，但清醒時守正可安。因此評為偏弱。", "婚姻": "第51籤把局面寫成醉中未有亂顛狂，最後以早晚虔燒一柱香收束。套用到婚姻，應理解為外在夢兆令人不安，但清醒時守正可安；在婚約、家庭共識、責任與長期相處上屬偏弱。", "人際": "問人際時，詩中夜夢堪嗟大不祥指出起因，早晚虔燒一柱香交代結果。兩者合看，表示外在夢兆令人不安，但清醒時守正可安。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "感情": "夢凶心正不是抽象好壞，而是一個有條件的過程：醉中未有亂顛狂顯示限制，但存心正相安處顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為偏弱。", "出行": "此項要從夜夢堪嗟大不祥與但存心正相安處的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是外在夢兆令人不安，但清醒時守正可安。因此評為偏弱。", "家宅": "第51籤把局面寫成醉中未有亂顛狂，最後以早晚虔燒一柱香收束。套用到家宅，應理解為外在夢兆令人不安，但清醒時守正可安；在家庭安寧、居所、修繕與財產安排上屬偏弱。", "修心建議": "問修心建議時，詩中夜夢堪嗟大不祥指出起因，早晚虔燒一柱香交代結果。兩者合看，表示外在夢兆令人不安，但清醒時守正可安。這項判為偏弱，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用夜夢堪嗟大不祥確認現況，再以醉中未有亂顛狂找出限制，觀察但存心正相安處所示轉折，最後依早晚虔燒一柱香設定完成或停止條件。此籤的實際行動核心是：外在夢兆令人不安，但清醒時守正可安。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 52, "displayNo": "第52籤", "level": "偏弱", "title": "保生大帝第52籤", "poem": ["一心雖急馬行遲", "扁舟欲渡遇風時", "等待明朝鼓浪息", "還君自在任遷移"], "story": "【風息再渡】這是一首以交通條件決定時機的等待籤。", "classicMeaning": "", "plainMeaning": "第52籤主題為風息再渡。四句由一心雖急馬行遲起筆，經扁舟欲渡遇風時與等待明朝鼓浪息推進，以還君自在任遷移收束。整體指出：心急無助於慢馬與逆風，等待風浪平息再遷移。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從一心雖急馬行遲與等待明朝鼓浪息的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是心急無助於慢馬與逆風，等待風浪平息再遷移。因此評為偏弱。", "考試": "第52籤把局面寫成扁舟欲渡遇風時，最後以還君自在任遷移收束。套用到考試，應理解為心急無助於慢馬與逆風，等待風浪平息再遷移；在準備深度、評核時機與臨場表現上屬偏弱。", "求財": "問求財時，詩中一心雖急馬行遲指出起因，還君自在任遷移交代結果。兩者合看，表示心急無助於慢馬與逆風，等待風浪平息再遷移。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "失物": "風息再渡不是抽象好壞，而是一個有條件的過程：扁舟欲渡遇風時顯示限制，等待明朝鼓浪息顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為偏弱。", "健康": "此項要從一心雖急馬行遲與等待明朝鼓浪息的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是心急無助於慢馬與逆風，等待風浪平息再遷移。因此評為偏弱。", "總論": "第52籤把局面寫成扁舟欲渡遇風時，最後以還君自在任遷移收束。套用到總論，應理解為心急無助於慢馬與逆風，等待風浪平息再遷移；在整體局勢、主要限制與轉機上屬偏弱。", "婚姻": "問婚姻時，詩中一心雖急馬行遲指出起因，還君自在任遷移交代結果。兩者合看，表示心急無助於慢馬與逆風，等待風浪平息再遷移。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "人際": "風息再渡不是抽象好壞，而是一個有條件的過程：扁舟欲渡遇風時顯示限制，等待明朝鼓浪息顯示轉折。對信任、貴人、小人與溝通界線而言，整體為偏弱。", "感情": "此項要從一心雖急馬行遲與等待明朝鼓浪息的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是心急無助於慢馬與逆風，等待風浪平息再遷移。因此評為偏弱。", "出行": "第52籤把局面寫成扁舟欲渡遇風時，最後以還君自在任遷移收束。套用到出行，應理解為心急無助於慢馬與逆風，等待風浪平息再遷移；在交通條件、方向、時機與人身安全上屬偏弱。", "家宅": "問家宅時，詩中一心雖急馬行遲指出起因，還君自在任遷移交代結果。兩者合看，表示心急無助於慢馬與逆風，等待風浪平息再遷移。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "修心建議": "風息再渡不是抽象好壞，而是一個有條件的過程：扁舟欲渡遇風時顯示限制，等待明朝鼓浪息顯示轉折。對品格、節制、反省與實際改過而言，整體為偏弱。"}, "actionAdvice": ["先用一心雖急馬行遲確認現況，再以扁舟欲渡遇風時找出限制，觀察等待明朝鼓浪息所示轉折，最後依還君自在任遷移設定完成或停止條件。此籤的實際行動核心是：心急無助於慢馬與逆風，等待風浪平息再遷移。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 53, "displayNo": "第53籤", "level": "偏弱", "title": "保生大帝第53籤", "poem": ["子欲養親親罔在", "樹欲靜時風不停", "出入行藏休再問", "勸君且去守安寧"], "story": "【及時行孝】《韓詩外傳》所傳皋魚以樹欲靜而風不止、子欲養而親不待感嘆行孝不及。", "classicMeaning": "", "plainMeaning": "第53籤主題為及時行孝。四句由子欲養親親罔在起筆，經樹欲靜時風不停與出入行藏休再問推進，以勸君且去守安寧收束。整體指出：親在時應盡養，錯過便不可追回。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第53籤把局面寫成樹欲靜時風不停，最後以勸君且去守安寧收束。套用到事業，應理解為親在時應盡養，錯過便不可追回；在職位、合作、執行條件與責任界線上屬偏弱。", "考試": "問考試時，詩中子欲養親親罔在指出起因，勸君且去守安寧交代結果。兩者合看，表示親在時應盡養，錯過便不可追回。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "求財": "及時行孝不是抽象好壞，而是一個有條件的過程：樹欲靜時風不停顯示限制，出入行藏休再問顯示轉折。對收入來源、交易成本、回收與風險而言，整體為偏弱。", "失物": "此項要從子欲養親親罔在與出入行藏休再問的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是親在時應盡養，錯過便不可追回。因此評為偏弱。", "健康": "第53籤把局面寫成樹欲靜時風不停，最後以勸君且去守安寧收束。套用到健康，應理解為親在時應盡養，錯過便不可追回；在症狀變化、診療、休養與危險徵象上屬偏弱。", "總論": "問總論時，詩中子欲養親親罔在指出起因，勸君且去守安寧交代結果。兩者合看，表示親在時應盡養，錯過便不可追回。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "婚姻": "及時行孝不是抽象好壞，而是一個有條件的過程：樹欲靜時風不停顯示限制，出入行藏休再問顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為偏弱。", "人際": "此項要從子欲養親親罔在與出入行藏休再問的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是親在時應盡養，錯過便不可追回。因此評為偏弱。", "感情": "第53籤把局面寫成樹欲靜時風不停，最後以勸君且去守安寧收束。套用到感情，應理解為親在時應盡養，錯過便不可追回；在雙方意願、互動品質與情緒安全上屬偏弱。", "出行": "問出行時，詩中子欲養親親罔在指出起因，勸君且去守安寧交代結果。兩者合看，表示親在時應盡養，錯過便不可追回。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "家宅": "及時行孝不是抽象好壞，而是一個有條件的過程：樹欲靜時風不停顯示限制，出入行藏休再問顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為偏弱。", "修心建議": "此項要從子欲養親親罔在與出入行藏休再問的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是親在時應盡養，錯過便不可追回。因此評為偏弱。"}, "actionAdvice": ["先用子欲養親親罔在確認現況，再以樹欲靜時風不停找出限制，觀察出入行藏休再問所示轉折，最後依勸君且去守安寧設定完成或停止條件。此籤的實際行動核心是：親在時應盡養，錯過便不可追回。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 54, "displayNo": "第54籤", "level": "偏弱", "title": "保生大帝第54籤", "poem": ["斜日寒風入暮天", "絲綸懶下莫移船", "潮來水泛魚難覓", "且向蓑衣臥雪眠"], "story": "【寒潮罷釣】斜日、寒風、蓑衣、臥雪構成停止求取的冬景。", "classicMeaning": "", "plainMeaning": "第54籤主題為寒潮罷釣。四句由斜日寒風入暮天起筆，經絲綸懶下莫移船與潮來水泛魚難覓推進，以且向蓑衣臥雪眠收束。整體指出：天寒潮泛，魚難尋，宜收線休息。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中斜日寒風入暮天指出起因，且向蓑衣臥雪眠交代結果。兩者合看，表示天寒潮泛，魚難尋，宜收線休息。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "考試": "寒潮罷釣不是抽象好壞，而是一個有條件的過程：絲綸懶下莫移船顯示限制，潮來水泛魚難覓顯示轉折。對準備深度、評核時機與臨場表現而言，整體為偏弱。", "求財": "此項要從斜日寒風入暮天與潮來水泛魚難覓的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是天寒潮泛，魚難尋，宜收線休息。因此評為偏弱。", "失物": "第54籤把局面寫成絲綸懶下莫移船，最後以且向蓑衣臥雪眠收束。套用到失物，應理解為天寒潮泛，魚難尋，宜收線休息；在遺失路徑、可追查線索與尋回時效上屬偏弱。", "健康": "問健康時，詩中斜日寒風入暮天指出起因，且向蓑衣臥雪眠交代結果。兩者合看，表示天寒潮泛，魚難尋，宜收線休息。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "總論": "寒潮罷釣不是抽象好壞，而是一個有條件的過程：絲綸懶下莫移船顯示限制，潮來水泛魚難覓顯示轉折。對整體局勢、主要限制與轉機而言，整體為偏弱。", "婚姻": "此項要從斜日寒風入暮天與潮來水泛魚難覓的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是天寒潮泛，魚難尋，宜收線休息。因此評為偏弱。", "人際": "第54籤把局面寫成絲綸懶下莫移船，最後以且向蓑衣臥雪眠收束。套用到人際，應理解為天寒潮泛，魚難尋，宜收線休息；在信任、貴人、小人與溝通界線上屬偏弱。", "感情": "問感情時，詩中斜日寒風入暮天指出起因，且向蓑衣臥雪眠交代結果。兩者合看，表示天寒潮泛，魚難尋，宜收線休息。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "出行": "寒潮罷釣不是抽象好壞，而是一個有條件的過程：絲綸懶下莫移船顯示限制，潮來水泛魚難覓顯示轉折。對交通條件、方向、時機與人身安全而言，整體為凶。", "家宅": "此項要從斜日寒風入暮天與潮來水泛魚難覓的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是天寒潮泛，魚難尋，宜收線休息。因此評為偏弱。", "修心建議": "第54籤把局面寫成絲綸懶下莫移船，最後以且向蓑衣臥雪眠收束。套用到修心建議，應理解為天寒潮泛，魚難尋，宜收線休息；在品格、節制、反省與實際改過上屬偏弱。"}, "actionAdvice": ["先用斜日寒風入暮天確認現況，再以絲綸懶下莫移船找出限制，觀察潮來水泛魚難覓所示轉折，最後依且向蓑衣臥雪眠設定完成或停止條件。此籤的實際行動核心是：天寒潮泛，魚難尋，宜收線休息。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 55, "displayNo": "第55籤", "level": "吉", "title": "保生大帝第55籤", "poem": ["急上雲梯步月宮", "嫦娥與我桂花香", "騎鯨變化凌雲志", "一任扶搖入九重"], "story": "【月宮高舉】嫦娥、月宮、桂花來自月宮神話；扶搖九重呼應《莊子》高飛意象。", "classicMeaning": "", "plainMeaning": "第55籤主題為月宮高舉。四句由急上雲梯步月宮起筆，經嫦娥與我桂花香與騎鯨變化凌雲志推進，以一任扶搖入九重收束。整體指出：志向高遠、功名上升，但需實力承接。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "月宮高舉不是抽象好壞，而是一個有條件的過程：嫦娥與我桂花香顯示限制，騎鯨變化凌雲志顯示轉折。對職位、合作、執行條件與責任界線而言，整體為吉。", "考試": "此項要從急上雲梯步月宮與騎鯨變化凌雲志的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是志向高遠、功名上升，但需實力承接。因此評為吉。", "求財": "第55籤把局面寫成嫦娥與我桂花香，最後以一任扶搖入九重收束。套用到求財，應理解為志向高遠、功名上升，但需實力承接；在收入來源、交易成本、回收與風險上屬吉。", "失物": "問失物時，詩中急上雲梯步月宮指出起因，一任扶搖入九重交代結果。兩者合看，表示志向高遠、功名上升，但需實力承接。這項判為吉，須以實際條件是否符合詩中轉機為準。", "健康": "月宮高舉不是抽象好壞，而是一個有條件的過程：嫦娥與我桂花香顯示限制，騎鯨變化凌雲志顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為吉。", "總論": "此項要從急上雲梯步月宮與騎鯨變化凌雲志的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是志向高遠、功名上升，但需實力承接。因此評為吉。", "婚姻": "第55籤把局面寫成嫦娥與我桂花香，最後以一任扶搖入九重收束。套用到婚姻，應理解為志向高遠、功名上升，但需實力承接；在婚約、家庭共識、責任與長期相處上屬吉。", "人際": "問人際時，詩中急上雲梯步月宮指出起因，一任扶搖入九重交代結果。兩者合看，表示志向高遠、功名上升，但需實力承接。這項判為吉，須以實際條件是否符合詩中轉機為準。", "感情": "月宮高舉不是抽象好壞，而是一個有條件的過程：嫦娥與我桂花香顯示限制，騎鯨變化凌雲志顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為吉。", "出行": "此項要從急上雲梯步月宮與騎鯨變化凌雲志的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是志向高遠、功名上升，但需實力承接。因此評為大吉。", "家宅": "第55籤把局面寫成嫦娥與我桂花香，最後以一任扶搖入九重收束。套用到家宅，應理解為志向高遠、功名上升，但需實力承接；在家庭安寧、居所、修繕與財產安排上屬吉。", "修心建議": "問修心建議時，詩中急上雲梯步月宮指出起因，一任扶搖入九重交代結果。兩者合看，表示志向高遠、功名上升，但需實力承接。這項判為吉，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用急上雲梯步月宮確認現況，再以嫦娥與我桂花香找出限制，觀察騎鯨變化凌雲志所示轉折，最後依一任扶搖入九重設定完成或停止條件。此籤的實際行動核心是：志向高遠、功名上升，但需實力承接。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 56, "displayNo": "第56籤", "level": "吉", "title": "保生大帝第56籤", "poem": ["令行到手宛相投", "自唱自吟卻自由", "雞犬相聞消息近", "姻緣夙世不須求"], "story": "【夙緣相投】雞犬相聞出自近鄰生活語境，表示消息與距離都近。", "classicMeaning": "", "plainMeaning": "第56籤主題為夙緣相投。四句由令行到手宛相投起筆，經自唱自吟卻自由與雞犬相聞消息近推進，以姻緣夙世不須求收束。整體指出：文令到手、消息接近，姻緣自然相合。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從令行到手宛相投與雞犬相聞消息近的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是文令到手、消息接近，姻緣自然相合。因此評為吉。", "考試": "第56籤把局面寫成自唱自吟卻自由，最後以姻緣夙世不須求收束。套用到考試，應理解為文令到手、消息接近，姻緣自然相合；在準備深度、評核時機與臨場表現上屬吉。", "求財": "問求財時，詩中令行到手宛相投指出起因，姻緣夙世不須求交代結果。兩者合看，表示文令到手、消息接近，姻緣自然相合。這項判為吉，須以實際條件是否符合詩中轉機為準。", "失物": "夙緣相投不是抽象好壞，而是一個有條件的過程：自唱自吟卻自由顯示限制，雞犬相聞消息近顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為吉。", "健康": "此項要從令行到手宛相投與雞犬相聞消息近的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是文令到手、消息接近，姻緣自然相合。因此評為吉。", "總論": "第56籤把局面寫成自唱自吟卻自由，最後以姻緣夙世不須求收束。套用到總論，應理解為文令到手、消息接近，姻緣自然相合；在整體局勢、主要限制與轉機上屬吉。", "婚姻": "問婚姻時，詩中令行到手宛相投指出起因，姻緣夙世不須求交代結果。兩者合看，表示文令到手、消息接近，姻緣自然相合。這項判為大吉，須以實際條件是否符合詩中轉機為準。", "人際": "夙緣相投不是抽象好壞，而是一個有條件的過程：自唱自吟卻自由顯示限制，雞犬相聞消息近顯示轉折。對信任、貴人、小人與溝通界線而言，整體為吉。", "感情": "此項要從令行到手宛相投與雞犬相聞消息近的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是文令到手、消息接近，姻緣自然相合。因此評為大吉。", "出行": "第56籤把局面寫成自唱自吟卻自由，最後以姻緣夙世不須求收束。套用到出行，應理解為文令到手、消息接近，姻緣自然相合；在交通條件、方向、時機與人身安全上屬吉。", "家宅": "問家宅時，詩中令行到手宛相投指出起因，姻緣夙世不須求交代結果。兩者合看，表示文令到手、消息接近，姻緣自然相合。這項判為吉，須以實際條件是否符合詩中轉機為準。", "修心建議": "夙緣相投不是抽象好壞，而是一個有條件的過程：自唱自吟卻自由顯示限制，雞犬相聞消息近顯示轉折。對品格、節制、反省與實際改過而言，整體為吉。"}, "actionAdvice": ["先用令行到手宛相投確認現況，再以自唱自吟卻自由找出限制，觀察雞犬相聞消息近所示轉折，最後依姻緣夙世不須求設定完成或停止條件。此籤的實際行動核心是：文令到手、消息接近，姻緣自然相合。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 57, "displayNo": "第57籤", "level": "吉", "title": "保生大帝第57籤", "poem": ["萬里求仙意甚虔", "青山重疊水連天", "終尋隱道桃源洞", "不覺回來坐碧蓮"], "story": "【求仙入桃源】桃源洞承接陶淵明《桃花源記》所形成的隱逸理想。", "classicMeaning": "", "plainMeaning": "第57籤主題為求仙入桃源。四句由萬里求仙意甚虔起筆，經青山重疊水連天與終尋隱道桃源洞推進，以不覺回來坐碧蓮收束。整體指出：虔誠遠求，終入隱境而得心靈轉化。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "第57籤把局面寫成青山重疊水連天，最後以不覺回來坐碧蓮收束。套用到事業，應理解為虔誠遠求，終入隱境而得心靈轉化；在職位、合作、執行條件與責任界線上屬吉。", "考試": "問考試時，詩中萬里求仙意甚虔指出起因，不覺回來坐碧蓮交代結果。兩者合看，表示虔誠遠求，終入隱境而得心靈轉化。這項判為吉，須以實際條件是否符合詩中轉機為準。", "求財": "求仙入桃源不是抽象好壞，而是一個有條件的過程：青山重疊水連天顯示限制，終尋隱道桃源洞顯示轉折。對收入來源、交易成本、回收與風險而言，整體為吉。", "失物": "此項要從萬里求仙意甚虔與終尋隱道桃源洞的轉折判斷。就遺失路徑、可追查線索與尋回時效而言，重點不是單看吉凶，而是虔誠遠求，終入隱境而得心靈轉化。因此評為吉。", "健康": "第57籤把局面寫成青山重疊水連天，最後以不覺回來坐碧蓮收束。套用到健康，應理解為虔誠遠求，終入隱境而得心靈轉化；在症狀變化、診療、休養與危險徵象上屬吉。", "總論": "問總論時，詩中萬里求仙意甚虔指出起因，不覺回來坐碧蓮交代結果。兩者合看，表示虔誠遠求，終入隱境而得心靈轉化。這項判為吉，須以實際條件是否符合詩中轉機為準。", "婚姻": "求仙入桃源不是抽象好壞，而是一個有條件的過程：青山重疊水連天顯示限制，終尋隱道桃源洞顯示轉折。對婚約、家庭共識、責任與長期相處而言，整體為吉。", "人際": "此項要從萬里求仙意甚虔與終尋隱道桃源洞的轉折判斷。就信任、貴人、小人與溝通界線而言，重點不是單看吉凶，而是虔誠遠求，終入隱境而得心靈轉化。因此評為吉。", "感情": "第57籤把局面寫成青山重疊水連天，最後以不覺回來坐碧蓮收束。套用到感情，應理解為虔誠遠求，終入隱境而得心靈轉化；在雙方意願、互動品質與情緒安全上屬吉。", "出行": "問出行時，詩中萬里求仙意甚虔指出起因，不覺回來坐碧蓮交代結果。兩者合看，表示虔誠遠求，終入隱境而得心靈轉化。這項判為吉，須以實際條件是否符合詩中轉機為準。", "家宅": "求仙入桃源不是抽象好壞，而是一個有條件的過程：青山重疊水連天顯示限制，終尋隱道桃源洞顯示轉折。對家庭安寧、居所、修繕與財產安排而言，整體為吉。", "修心建議": "此項要從萬里求仙意甚虔與終尋隱道桃源洞的轉折判斷。就品格、節制、反省與實際改過而言，重點不是單看吉凶，而是虔誠遠求，終入隱境而得心靈轉化。因此評為吉。"}, "actionAdvice": ["先用萬里求仙意甚虔確認現況，再以青山重疊水連天找出限制，觀察終尋隱道桃源洞所示轉折，最後依不覺回來坐碧蓮設定完成或停止條件。此籤的實際行動核心是：虔誠遠求，終入隱境而得心靈轉化。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 58, "displayNo": "第58籤", "level": "平", "title": "保生大帝第58籤", "poem": ["靜心修煉學真仙", "蝴蝶飛來豈偶然", "不覺狂風吹去後", "丹青依舊是前緣"], "story": "【蝶來緣續】蝴蝶可參照莊周夢蝶，但籤詩未直接點名莊子，因此不寫成固定人物故事。", "classicMeaning": "", "plainMeaning": "第58籤主題為蝶來緣續。四句由靜心修煉學真仙起筆，經蝴蝶飛來豈偶然與不覺狂風吹去後推進，以丹青依舊是前緣收束。整體指出：修煉中遭風變，表象散去而前緣仍存。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "問事業時，詩中靜心修煉學真仙指出起因，丹青依舊是前緣交代結果。兩者合看，表示修煉中遭風變，表象散去而前緣仍存。這項判為平，須以實際條件是否符合詩中轉機為準。", "考試": "蝶來緣續不是抽象好壞，而是一個有條件的過程：蝴蝶飛來豈偶然顯示限制，不覺狂風吹去後顯示轉折。對準備深度、評核時機與臨場表現而言，整體為平。", "求財": "此項要從靜心修煉學真仙與不覺狂風吹去後的轉折判斷。就收入來源、交易成本、回收與風險而言，重點不是單看吉凶，而是修煉中遭風變，表象散去而前緣仍存。因此評為平。", "失物": "第58籤把局面寫成蝴蝶飛來豈偶然，最後以丹青依舊是前緣收束。套用到失物，應理解為修煉中遭風變，表象散去而前緣仍存；在遺失路徑、可追查線索與尋回時效上屬平。", "健康": "問健康時，詩中靜心修煉學真仙指出起因，丹青依舊是前緣交代結果。兩者合看，表示修煉中遭風變，表象散去而前緣仍存。這項判為平，須以實際條件是否符合詩中轉機為準。", "總論": "蝶來緣續不是抽象好壞，而是一個有條件的過程：蝴蝶飛來豈偶然顯示限制，不覺狂風吹去後顯示轉折。對整體局勢、主要限制與轉機而言，整體為平。", "婚姻": "此項要從靜心修煉學真仙與不覺狂風吹去後的轉折判斷。就婚約、家庭共識、責任與長期相處而言，重點不是單看吉凶，而是修煉中遭風變，表象散去而前緣仍存。因此評為平。", "人際": "第58籤把局面寫成蝴蝶飛來豈偶然，最後以丹青依舊是前緣收束。套用到人際，應理解為修煉中遭風變，表象散去而前緣仍存；在信任、貴人、小人與溝通界線上屬平。", "感情": "問感情時，詩中靜心修煉學真仙指出起因，丹青依舊是前緣交代結果。兩者合看，表示修煉中遭風變，表象散去而前緣仍存。這項判為平，須以實際條件是否符合詩中轉機為準。", "出行": "蝶來緣續不是抽象好壞，而是一個有條件的過程：蝴蝶飛來豈偶然顯示限制，不覺狂風吹去後顯示轉折。對交通條件、方向、時機與人身安全而言，整體為平。", "家宅": "此項要從靜心修煉學真仙與不覺狂風吹去後的轉折判斷。就家庭安寧、居所、修繕與財產安排而言，重點不是單看吉凶，而是修煉中遭風變，表象散去而前緣仍存。因此評為平。", "修心建議": "第58籤把局面寫成蝴蝶飛來豈偶然，最後以丹青依舊是前緣收束。套用到修心建議，應理解為修煉中遭風變，表象散去而前緣仍存；在品格、節制、反省與實際改過上屬平。"}, "actionAdvice": ["先用靜心修煉學真仙確認現況，再以蝴蝶飛來豈偶然找出限制，觀察不覺狂風吹去後所示轉折，最後依丹青依舊是前緣設定完成或停止條件。此籤的實際行動核心是：修煉中遭風變，表象散去而前緣仍存。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 59, "displayNo": "第59籤", "level": "吉", "title": "保生大帝第59籤", "poem": ["虔意求神禱必靈", "醉中邪魅不須驚", "誠心自有真神在", "誰道虛空無報應"], "story": "【誠心不驚】重點是內心穩定及行為端正，不應鼓勵以求籤取代醫療。", "classicMeaning": "", "plainMeaning": "第59籤主題為誠心不驚。四句由虔意求神禱必靈起筆，經醉中邪魅不須驚與誠心自有真神在推進，以誰道虛空無報應收束。整體指出：邪魅與醉中驚擾，不敵持正與虔誠。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "誠心不驚不是抽象好壞，而是一個有條件的過程：醉中邪魅不須驚顯示限制，誠心自有真神在顯示轉折。對職位、合作、執行條件與責任界線而言，整體為吉。", "考試": "此項要從虔意求神禱必靈與誠心自有真神在的轉折判斷。就準備深度、評核時機與臨場表現而言，重點不是單看吉凶，而是邪魅與醉中驚擾，不敵持正與虔誠。因此評為吉。", "求財": "第59籤把局面寫成醉中邪魅不須驚，最後以誰道虛空無報應收束。套用到求財，應理解為邪魅與醉中驚擾，不敵持正與虔誠；在收入來源、交易成本、回收與風險上屬吉。", "失物": "問失物時，詩中虔意求神禱必靈指出起因，誰道虛空無報應交代結果。兩者合看，表示邪魅與醉中驚擾，不敵持正與虔誠。這項判為吉，須以實際條件是否符合詩中轉機為準。", "健康": "誠心不驚不是抽象好壞，而是一個有條件的過程：醉中邪魅不須驚顯示限制，誠心自有真神在顯示轉折。對症狀變化、診療、休養與危險徵象而言，整體為吉。", "總論": "此項要從虔意求神禱必靈與誠心自有真神在的轉折判斷。就整體局勢、主要限制與轉機而言，重點不是單看吉凶，而是邪魅與醉中驚擾，不敵持正與虔誠。因此評為吉。", "婚姻": "第59籤把局面寫成醉中邪魅不須驚，最後以誰道虛空無報應收束。套用到婚姻，應理解為邪魅與醉中驚擾，不敵持正與虔誠；在婚約、家庭共識、責任與長期相處上屬吉。", "人際": "問人際時，詩中虔意求神禱必靈指出起因，誰道虛空無報應交代結果。兩者合看，表示邪魅與醉中驚擾，不敵持正與虔誠。這項判為吉，須以實際條件是否符合詩中轉機為準。", "感情": "誠心不驚不是抽象好壞，而是一個有條件的過程：醉中邪魅不須驚顯示限制，誠心自有真神在顯示轉折。對雙方意願、互動品質與情緒安全而言，整體為吉。", "出行": "此項要從虔意求神禱必靈與誠心自有真神在的轉折判斷。就交通條件、方向、時機與人身安全而言，重點不是單看吉凶，而是邪魅與醉中驚擾，不敵持正與虔誠。因此評為吉。", "家宅": "第59籤把局面寫成醉中邪魅不須驚，最後以誰道虛空無報應收束。套用到家宅，應理解為邪魅與醉中驚擾，不敵持正與虔誠；在家庭安寧、居所、修繕與財產安排上屬吉。", "修心建議": "問修心建議時，詩中虔意求神禱必靈指出起因，誰道虛空無報應交代結果。兩者合看，表示邪魅與醉中驚擾，不敵持正與虔誠。這項判為吉，須以實際條件是否符合詩中轉機為準。"}, "actionAdvice": ["先用虔意求神禱必靈確認現況，再以醉中邪魅不須驚找出限制，觀察誠心自有真神在所示轉折，最後依誰道虛空無報應設定完成或停止條件。此籤的實際行動核心是：邪魅與醉中驚擾，不敵持正與虔誠。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 60, "displayNo": "第60籤", "level": "偏弱", "title": "保生大帝第60籤", "poem": ["來意不誠禱不靈", "不誠祈禱枉勞心", "欲知無限神機事", "盡在虔心一點清"], "story": "【一點虔清】末籤直接反省求籤者動機，是整套籤系的倫理收束。", "classicMeaning": "", "plainMeaning": "第60籤主題為一點虔清。四句由來意不誠禱不靈起筆，經不誠祈禱枉勞心與欲知無限神機事推進，以盡在虔心一點清收束。整體指出：求問的前提是誠實與清明，不誠則所得無效。解讀時要保留詩中的先後條件，不能只抽取一句當成保證。", "categoryReadings": {"事業": "此項要從來意不誠禱不靈與欲知無限神機事的轉折判斷。就職位、合作、執行條件與責任界線而言，重點不是單看吉凶，而是求問的前提是誠實與清明，不誠則所得無效。因此評為偏弱。", "考試": "第60籤把局面寫成不誠祈禱枉勞心，最後以盡在虔心一點清收束。套用到考試，應理解為求問的前提是誠實與清明，不誠則所得無效；在準備深度、評核時機與臨場表現上屬偏弱。", "求財": "問求財時，詩中來意不誠禱不靈指出起因，盡在虔心一點清交代結果。兩者合看，表示求問的前提是誠實與清明，不誠則所得無效。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "失物": "一點虔清不是抽象好壞，而是一個有條件的過程：不誠祈禱枉勞心顯示限制，欲知無限神機事顯示轉折。對遺失路徑、可追查線索與尋回時效而言，整體為偏弱。", "健康": "此項要從來意不誠禱不靈與欲知無限神機事的轉折判斷。就症狀變化、診療、休養與危險徵象而言，重點不是單看吉凶，而是求問的前提是誠實與清明，不誠則所得無效。因此評為偏弱。", "總論": "第60籤把局面寫成不誠祈禱枉勞心，最後以盡在虔心一點清收束。套用到總論，應理解為求問的前提是誠實與清明，不誠則所得無效；在整體局勢、主要限制與轉機上屬偏弱。", "婚姻": "問婚姻時，詩中來意不誠禱不靈指出起因，盡在虔心一點清交代結果。兩者合看，表示求問的前提是誠實與清明，不誠則所得無效。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "人際": "一點虔清不是抽象好壞，而是一個有條件的過程：不誠祈禱枉勞心顯示限制，欲知無限神機事顯示轉折。對信任、貴人、小人與溝通界線而言，整體為偏弱。", "感情": "此項要從來意不誠禱不靈與欲知無限神機事的轉折判斷。就雙方意願、互動品質與情緒安全而言，重點不是單看吉凶，而是求問的前提是誠實與清明，不誠則所得無效。因此評為偏弱。", "出行": "第60籤把局面寫成不誠祈禱枉勞心，最後以盡在虔心一點清收束。套用到出行，應理解為求問的前提是誠實與清明，不誠則所得無效；在交通條件、方向、時機與人身安全上屬偏弱。", "家宅": "問家宅時，詩中來意不誠禱不靈指出起因，盡在虔心一點清交代結果。兩者合看，表示求問的前提是誠實與清明，不誠則所得無效。這項判為偏弱，須以實際條件是否符合詩中轉機為準。", "修心建議": "一點虔清不是抽象好壞，而是一個有條件的過程：不誠祈禱枉勞心顯示限制，欲知無限神機事顯示轉折。對品格、節制、反省與實際改過而言，整體為偏弱。"}, "actionAdvice": ["先用來意不誠禱不靈確認現況，再以不誠祈禱枉勞心找出限制，觀察欲知無限神機事所示轉折，最後依盡在虔心一點清設定完成或停止條件。此籤的實際行動核心是：求問的前提是誠實與清明，不誠則所得無效。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}}
];

